{
  "name": "ShiftPlan Pro",
  "description": "A modern weekly shift planning application inspired by Teams Shifts. Manage users, create reusable shift templates, and organize your team's schedule efficiently."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  name: string;
  role: string;
  avatar?: string;
}

export interface ShiftTemplate {
  id: string;
  label: string; // e.g., "8h-16h" or "Matin"
  code: string;  // Short code e.g., "M" or "8h"
  color: string; // Tailwind color class or hex
  description?: string;
}

export interface Assignment {
  id: string;
  userId: string;
  date: string; // ISO Date string YYYY-MM-DD
  templateId: string;
}

export interface ViewState {
  currentDate: Date;
  isAdminOpen: boolean;
}

export const getStartOfWeek = (date: Date): Date => {
  const day = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1); // Adjust when day is Sunday
  const newDate = new Date(date);
  newDate.setDate(diff);
  newDate.setHours(0, 0, 0, 0);
  return newDate;
};

export const addDays = (date: Date, days: number): Date => {
  const result = new Date(date);
  result.setDate(result.getDate() + days);
  return result;
};

export const formatDateISO = (date: Date): string => {
  const offset = date.getTimezoneOffset();
  const adjustedDate = new Date(date.getTime() - (offset*60*1000));
  return adjustedDate.toISOString().split('T')[0];
};

export const formatDateFr = (date: Date): string => {
  return new Intl.DateTimeFormat('fr-FR', {
    weekday: 'short',
    day: 'numeric',
    month: 'short'
  }).format(date);
};

export const getWeekRangeString = (date: Date): string => {
  const start = getStartOfWeek(date);
  const end = addDays(start, 6);
  const options: Intl.DateTimeFormatOptions = { day: 'numeric', month: 'long' };
  return `${new Intl.DateTimeFormat('fr-FR', options).format(start)} - ${new Intl.DateTimeFormat('fr-FR', options).format(end)}`;
};

import { useState, useEffect, useCallback } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { INITIAL_USERS, INITIAL_TEMPLATES } from '../constants';
import { formatDateISO } from '../utils/dateUtils';

export const usePlanner = () => {
  // Load initial state from localStorage or defaults
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('shiftplan_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [templates, setTemplates] = useState<ShiftTemplate[]>(() => {
    const saved = localStorage.getItem('shiftplan_templates');
    return saved ? JSON.parse(saved) : INITIAL_TEMPLATES;
  });

  const [assignments, setAssignments] = useState<Assignment[]>(() => {
    const saved = localStorage.getItem('shiftplan_assignments');
    return saved ? JSON.parse(saved) : [];
  });

  // Persistence effects
  useEffect(() => { localStorage.setItem('shiftplan_users', JSON.stringify(users)); }, [users]);
  useEffect(() => { localStorage.setItem('shiftplan_templates', JSON.stringify(templates)); }, [templates]);
  useEffect(() => { localStorage.setItem('shiftplan_assignments', JSON.stringify(assignments)); }, [assignments]);

  // Actions
  const addUser = (user: User) => setUsers([...users, user]);
  const removeUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
    setAssignments(assignments.filter(a => a.userId !== id));
  };
  const updateUser = (updated: User) => {
    setUsers(users.map(u => u.id === updated.id ? updated : u));
  };

  const addTemplate = (tpl: ShiftTemplate) => setTemplates([...templates, tpl]);
  const removeTemplate = (id: string) => {
    setTemplates(templates.filter(t => t.id !== id));
    setAssignments(assignments.filter(a => a.templateId !== id));
  };
  const updateTemplate = (updated: ShiftTemplate) => {
    setTemplates(templates.map(t => t.id === updated.id ? updated : t));
  };

  const assignShift = (userId: string, date: Date, templateId: string | null) => {
    const dateStr = formatDateISO(date);
    if (templateId === null) {
      // Remove assignment
      setAssignments(prev => prev.filter(a => !(a.userId === userId && a.date === dateStr)));
    } else {
      // Add or Update assignment
      setAssignments(prev => {
        const existingIndex = prev.findIndex(a => a.userId === userId && a.date === dateStr);
        if (existingIndex >= 0) {
          const newAssignments = [...prev];
          newAssignments[existingIndex] = { ...newAssignments[existingIndex], templateId };
          return newAssignments;
        } else {
          return [...prev, { id: crypto.randomUUID(), userId, date: dateStr, templateId }];
        }
      });
    }
  };

  const getAssignment = useCallback((userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    return assignments.find(a => a.userId === userId && a.date === dateStr);
  }, [assignments]);

  return {
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    assignments, assignShift, getAssignment
  };
};

import React, { useState } from 'react';
import { User, ShiftTemplate } from '../types';
import { COLORS } from '../constants';
import { Trash2, Plus, User as UserIcon, Calendar, X } from 'lucide-react';

interface AdminPanelProps {
  users: User[];
  templates: ShiftTemplate[];
  onAddUser: (u: User) => void;
  onRemoveUser: (id: string) => void;
  onAddTemplate: (t: ShiftTemplate) => void;
  onRemoveTemplate: (id: string) => void;
  onClose: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({
  users, templates, onAddUser, onRemoveUser, onAddTemplate, onRemoveTemplate, onClose
}) => {
  const [activeTab, setActiveTab] = useState<'users' | 'templates'>('users');

  // New User Form State
  const [newUserName, setNewUserName] = useState('');
  const [newUserRole, setNewUserRole] = useState('');

  // New Template Form State
  const [newTplLabel, setNewTplLabel] = useState('');
  const [newTplCode, setNewTplCode] = useState('');
  const [newTplColor, setNewTplColor] = useState(COLORS[0].value);
  const [newTplDesc, setNewTplDesc] = useState('');

  const handleCreateUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUserName.trim()) return;
    onAddUser({
      id: crypto.randomUUID(),
      name: newUserName,
      role: newUserRole || 'Employé'
    });
    setNewUserName('');
    setNewUserRole('');
  };

  const handleCreateTemplate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTplLabel.trim() || !newTplCode.trim()) return;
    onAddTemplate({
      id: crypto.randomUUID(),
      label: newTplLabel,
      code: newTplCode,
      color: newTplColor,
      description: newTplDesc
    });
    setNewTplLabel('');
    setNewTplCode('');
    setNewTplDesc('');
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200">

        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-slate-50 rounded-t-xl">
          <h2 className="text-2xl font-bold text-slate-800">Administration</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <X className="w-6 h-6 text-slate-500" />
          </button>
        </div>

        {/* Tabs */}
        <div className="flex border-b">
          <button
            onClick={() => setActiveTab('users')}
            className={`flex-1 py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${activeTab === 'users' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <UserIcon className="w-4 h-4" />
            Utilisateurs
          </button>
          <button
            onClick={() => setActiveTab('templates')}
            className={`flex-1 py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${activeTab === 'templates' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'}`}
          >
            <Calendar className="w-4 h-4" />
            Modèles (Modules)
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-white">

          {activeTab === 'users' && (
            <div className="space-y-6">
              <form onSubmit={handleCreateUser} className="bg-slate-50 p-4 rounded-lg border border-slate-200 space-y-4">
                <h3 className="font-semibold text-sm uppercase tracking-wide text-slate-500">Ajouter un utilisateur</h3>
                <div className="flex gap-3">
                  <input
                    type="text"
                    placeholder="Nom complet"
                    className="flex-1 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={newUserName}
                    onChange={(e) => setNewUserName(e.target.value)}
                  />
                  <input
                    type="text"
                    placeholder="Rôle (ex: Manager)"
                    className="flex-1 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={newUserRole}
                    onChange={(e) => setNewUserRole(e.target.value)}
                  />
                  <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2">
                    <Plus className="w-4 h-4" /> Ajouter
                  </button>
                </div>
              </form>

              <div className="space-y-2">
                {users.map(user => (
                  <div key={user.id} className="flex items-center justify-between p-3 bg-white border rounded-lg hover:shadow-sm transition-shadow">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center text-slate-600 font-bold text-xs">
                        {user.name.substring(0, 2).toUpperCase()}
                      </div>
                      <div>
                        <div className="font-medium text-slate-800">{user.name}</div>
                        <div className="text-xs text-slate-500">{user.role}</div>
                      </div>
                    </div>
                    <button 
                      onClick={() => onRemoveUser(user.id)}
                      className="text-red-400 hover:text-red-600 p-2 hover:bg-red-50 rounded-full transition-colors"
                      title="Supprimer"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))}
                {users.length === 0 && <p className="text-center text-slate-400 py-4">Aucun utilisateur.</p>}
              </div>
            </div>
          )}

          {activeTab === 'templates' && (
            <div className="space-y-6">
              <form onSubmit={handleCreateTemplate} className="bg-slate-50 p-4 rounded-lg border border-slate-200 space-y-4">
                <h3 className="font-semibold text-sm uppercase tracking-wide text-slate-500">Créer un modèle</h3>
                <div className="grid grid-cols-2 gap-3">
                  <input
                    type="text"
                    placeholder="Nom (ex: Matin)"
                    className="px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={newTplLabel}
                    onChange={(e) => setNewTplLabel(e.target.value)}
                  />
                  <input
                    type="text"
                    placeholder="Code (ex: 8h)"
                    className="px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={newTplCode}
                    onChange={(e) => setNewTplCode(e.target.value)}
                    maxLength={5}
                  />
                  <input
                    type="text"
                    placeholder="Description (optionnel)"
                    className="col-span-2 px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                    value={newTplDesc}
                    onChange={(e) => setNewTplDesc(e.target.value)}
                  />
                </div>

                <div>
                  <label className="text-xs font-semibold text-slate-500 mb-2 block">Couleur</label>
                  <div className="flex flex-wrap gap-2">
                    {COLORS.map(c => (
                      <button
                        key={c.name}
                        type="button"
                        onClick={() => setNewTplColor(c.value)}
                        className={`w-8 h-8 rounded-full border-2 transition-transform hover:scale-110 ${c.value.split(' ')[0]} ${newTplColor === c.value ? 'ring-2 ring-offset-2 ring-blue-500 border-transparent' : 'border-transparent'}`}
                        title={c.name}
                      />
                    ))}
                  </div>
                </div>

                <div className="flex justify-end">
                   <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2">
                    <Plus className="w-4 h-4" /> Créer le modèle
                  </button>
                </div>
              </form>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {templates.map(tpl => (
                  <div key={tpl.id} className={`flex items-center justify-between p-3 border rounded-lg hover:shadow-sm transition-shadow border-l-4 ${tpl.color.replace('text-', 'border-').split(' ')[2]}`}>
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                         <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${tpl.color}`}>{tpl.code}</span>
                         <span className="font-medium text-slate-800">{tpl.label}</span>
                      </div>
                      {tpl.description && <div className="text-xs text-slate-500 mt-1">{tpl.description}</div>}
                    </div>
                    <button 
                      onClick={() => onRemoveTemplate(tpl.id)}
                      className="text-red-400 hover:text-red-600 p-2 hover:bg-red-50 rounded-full transition-colors"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { getStartOfWeek, addDays, formatDateFr, formatDateISO } from '../utils/dateUtils';
import { ChevronLeft, ChevronRight, Settings, Calendar as CalendarIcon, MoreVertical, Eraser } from 'lucide-react';

interface CalendarGridProps {
  currentDate: Date;
  onDateChange: (d: Date) => void;
  users: User[];
  templates: ShiftTemplate[];
  getAssignment: (userId: string, date: Date) => Assignment | undefined;
  onAssign: (userId: string, date: Date, templateId: string | null) => void;
  onOpenAdmin: () => void;
}

export const CalendarGrid: React.FC<CalendarGridProps> = ({
  currentDate, onDateChange, users, templates, getAssignment, onAssign, onOpenAdmin
}) => {
  const startOfWeek = getStartOfWeek(currentDate);
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(startOfWeek, i));
  const todayISO = formatDateISO(new Date());

  // Popover state for assigning templates
  const [popover, setPopover] = useState<{
    isOpen: boolean;
    userId: string | null;
    date: Date | null;
    x: number;
    y: number;
  }>({ isOpen: false, userId: null, date: null, x: 0, y: 0 });

  const popoverRef = useRef<HTMLDivElement>(null);

  // Close popover when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setPopover({ ...popover, isOpen: false });
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [popover]);

  const handleCellClick = (e: React.MouseEvent, userId: string, date: Date) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setPopover({
      isOpen: true,
      userId,
      date,
      x: rect.left + window.scrollX,
      y: rect.bottom + window.scrollY + 5 // slightly below
    });
  };

  const handleTemplateSelect = (templateId: string | null) => {
    if (popover.userId && popover.date) {
      onAssign(popover.userId, popover.date, templateId);
    }
    setPopover({ ...popover, isOpen: false });
  };

  return (
    <div className="flex flex-col h-full bg-white shadow-sm border rounded-xl overflow-hidden">
      {/* Calendar Header Controls */}
      <div className="flex items-center justify-between p-4 border-b bg-white">
        <div className="flex items-center gap-4">
          <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
            <button 
              onClick={() => onDateChange(addDays(currentDate, -7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <button 
              onClick={() => onDateChange(new Date())}
              className="px-3 py-1 text-sm font-medium text-slate-600 hover:bg-white hover:shadow-sm rounded-md transition-all"
            >
              Aujourd'hui
            </button>
            <button 
              onClick={() => onDateChange(addDays(currentDate, 7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
          <h2 className="text-lg font-bold text-slate-800 capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-blue-600" />
            {new Intl.DateTimeFormat('fr-FR', { month: 'long', year: 'numeric' }).format(currentDate)}
          </h2>
        </div>

        <button 
          onClick={onOpenAdmin}
          className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white text-sm font-medium rounded-lg hover:bg-slate-700 transition-colors shadow-sm"
        >
          <Settings className="w-4 h-4" />
          <span>Gérer l'équipe & Modèles</span>
        </button>
      </div>

      {/* Main Grid Area */}
      <div className="flex-1 overflow-auto relative">
        <table className="w-full border-collapse min-w-[1000px]">
          <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
            <tr>
              <th className="p-4 text-left border-b border-r w-64 bg-slate-50 sticky left-0 z-20">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Membres</span>
              </th>
              {weekDays.map((date) => {
                const isToday = formatDateISO(date) === todayISO;
                return (
                  <th key={date.toISOString()} className={`p-3 text-center border-b border-r min-w-[120px] ${isToday ? 'bg-blue-50/50' : ''}`}>
                    <div className={`flex flex-col items-center justify-center`}>
                      <span className={`text-xs uppercase font-bold mb-1 ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>
                        {new Intl.DateTimeFormat('fr-FR', { weekday: 'short' }).format(date)}
                      </span>
                      <span className={`text-xl font-light w-8 h-8 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id} className="group hover:bg-slate-50/50 transition-colors">
                <td className="p-4 border-b border-r bg-white sticky left-0 z-10 group-hover:bg-slate-50/50 border-r-slate-200">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold shadow-sm">
                       {user.name.charAt(0)}
                    </div>
                    <div>
                      <div className="font-semibold text-slate-900 text-sm">{user.name}</div>
                      <div className="text-xs text-slate-500">{user.role}</div>
                    </div>
                  </div>
                </td>
                {weekDays.map((date) => {
                  const assignment = getAssignment(user.id, date);
                  const template = assignment ? templates.find(t => t.id === assignment.templateId) : null;
                  const isToday = formatDateISO(date) === todayISO;

                  return (
                    <td 
                      key={date.toISOString()} 
                      className={`p-1 border-b border-r cursor-pointer relative transition-all ${isToday ? 'bg-blue-50/10' : ''}`}
                      onClick={(e) => handleCellClick(e, user.id, date)}
                    >
                      <div className={`w-full h-16 rounded-lg border-2 border-dashed border-transparent hover:border-blue-200 flex items-center justify-center transition-all ${!template ? 'opacity-0 hover:opacity-100' : ''}`}>
                        {template ? (
                           <div className={`w-full h-full mx-1 rounded-md p-2 shadow-sm border ${template.color} flex flex-col justify-center`}>
                             <div className="font-bold text-sm truncate text-center">{template.code}</div>
                             <div className="text-[10px] opacity-80 truncate text-center hidden xl:block">{template.label}</div>
                           </div>
                        ) : (
                          <Plus className="w-5 h-5 text-slate-300" />
                        )}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
            {users.length === 0 && (
              <tr>
                <td colSpan={8} className="p-12 text-center text-slate-400">
                  Aucun utilisateur défini. Utilisez le panneau d'administration pour commencer.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Popover Selection Menu */}
      {popover.isOpen && (
        <div 
          ref={popoverRef}
          className="fixed bg-white rounded-xl shadow-xl border border-slate-200 z-50 w-64 p-2 animate-in fade-in zoom-in-95 duration-100"
          style={{ top: popover.y, left: Math.min(popover.x, window.innerWidth - 270) }} // prevent overflow right
        >
          <div className="text-xs font-bold text-slate-400 uppercase px-2 py-1 mb-2">Choisir un module</div>
          <div className="space-y-1 max-h-60 overflow-y-auto">
            {templates.map(tpl => (
              <button
                key={tpl.id}
                onClick={() => handleTemplateSelect(tpl.id)}
                className={`w-full text-left p-2 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors flex items-center gap-2 group`}
              >
                <span className={`w-3 h-3 rounded-full ${tpl.color.split(' ')[0]}`}></span>
                <span className="flex-1">{tpl.label}</span>
                <span className="text-xs text-slate-400 font-mono bg-slate-100 px-1 rounded group-hover:bg-white">{tpl.code}</span>
              </button>
            ))}

            <div className="h-px bg-slate-100 my-1"></div>

            <button
               onClick={() => handleTemplateSelect(null)}
               className="w-full text-left p-2 rounded-lg text-sm font-medium text-red-500 hover:bg-red-50 transition-colors flex items-center gap-2"
            >
              <Eraser className="w-4 h-4" />
              Effacer
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { CalendarGrid } from './components/CalendarGrid';
import { AdminPanel } from './components/AdminPanel';
import { usePlanner } from './hooks/usePlanner';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isAdminOpen, setIsAdminOpen] = useState(false);

  const {
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    getAssignment, assignShift
  } = usePlanner();

  return (
    <div className="h-full flex flex-col bg-slate-100">
      {/* Top Navigation Bar */}
      <nav className="bg-white border-b px-6 py-3 flex items-center justify-between shadow-sm z-20">
