import React, { useState, useRef, useEffect } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { getStartOfWeek, addDays, formatDateFr, formatDateISO } from '../utils/dateUtils';
import { ChevronLeft, ChevronRight, Settings, Calendar as CalendarIcon, Check, Eraser, Plus, Type } from 'lucide-react';

interface CalendarGridProps {
  currentDate: Date;
  onDateChange: (d: Date) => void;
  users: User[];
  templates: ShiftTemplate[];
  getAssignment: (userId: string, date: Date) => Assignment | undefined;
  onToggleTemplate: (userId: string, date: Date, templateId: string) => void;
  onUpdateText: (userId: string, date: Date, text: string) => void;
  onClear: (userId: string, date: Date) => void;
  onOpenAdmin: () => void;
}

export const CalendarGrid: React.FC<CalendarGridProps> = ({
  currentDate, onDateChange, users, templates, getAssignment, onToggleTemplate, onUpdateText, onClear, onOpenAdmin
}) => {
  const startOfWeek = getStartOfWeek(currentDate);
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(startOfWeek, i));
  const todayISO = formatDateISO(new Date());

  // Popover state
  const [popover, setPopover] = useState<{
    isOpen: boolean;
    userId: string | null;
    date: Date | null;
    x: number;
    y: number;
  }>({ isOpen: false, userId: null, date: null, x: 0, y: 0 });

  // Local text state for the input in the popover
  const [localText, setLocalText] = useState('');

  const popoverRef = useRef<HTMLDivElement>(null);

  // Load existing text into local state when opening popover
  useEffect(() => {
    if (popover.isOpen && popover.userId && popover.date) {
        const assignment = getAssignment(popover.userId, popover.date);
        setLocalText(assignment?.customText || '');
    }
  }, [popover.isOpen, popover.userId, popover.date, getAssignment]);

  // Close popover when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setPopover({ ...popover, isOpen: false });
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [popover]);

  const handleCellClick = (e: React.MouseEvent, userId: string, date: Date) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();

    // Adjust position to stay on screen
    let x = rect.left + window.scrollX;
    if (x + 280 > window.innerWidth) {
        x = window.innerWidth - 290;
    }

    setPopover({
      isOpen: true,
      userId,
      date,
      x: x,
      y: rect.bottom + window.scrollY + 5
    });
  };

  const handleTextChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setLocalText(e.target.value);
      if (popover.userId && popover.date) {
          onUpdateText(popover.userId, popover.date, e.target.value);
      }
  };

  return (
    <div className="flex flex-col h-full bg-white shadow-sm border rounded-xl overflow-hidden">
      {/* Calendar Header Controls */}
      <div className="flex items-center justify-between p-4 border-b bg-white">
        <div className="flex items-center gap-4">
          <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
            <button 
              onClick={() => onDateChange(addDays(currentDate, -7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <button 
              onClick={() => onDateChange(new Date())}
              className="px-3 py-1 text-sm font-medium text-slate-600 hover:bg-white hover:shadow-sm rounded-md transition-all"
            >
              Aujourd'hui
            </button>
            <button 
              onClick={() => onDateChange(addDays(currentDate, 7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
          <h2 className="text-lg font-bold text-slate-800 capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-blue-600" />
            {new Intl.DateTimeFormat('fr-FR', { month: 'long', year: 'numeric' }).format(currentDate)}
          </h2>
        </div>

        <button 
          onClick={onOpenAdmin}
          className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white text-sm font-medium rounded-lg hover:bg-slate-700 transition-colors shadow-sm"
        >
          <Settings className="w-4 h-4" />
          <span>Gérer l'équipe & Modèles</span>
        </button>
      </div>

      {/* Main Grid Area */}
      <div className="flex-1 overflow-auto relative">
        <table className="w-full border-collapse min-w-[1000px]">
          <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
            <tr>
              <th className="p-4 text-left border-b border-r w-64 bg-slate-50 sticky left-0 z-20">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Membres</span>
              </th>
              {weekDays.map((date) => {
                const isToday = formatDateISO(date) === todayISO;
                return (
                  <th key={date.toISOString()} className={`p-3 text-center border-b border-r min-w-[120px] ${isToday ? 'bg-blue-50/50' : ''}`}>
                    <div className={`flex flex-col items-center justify-center`}>
                      <span className={`text-xs uppercase font-bold mb-1 ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>
                        {new Intl.DateTimeFormat('fr-FR', { weekday: 'short' }).format(date)}
                      </span>
                      <span className={`text-xl font-light w-8 h-8 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id} className="group hover:bg-slate-50/50 transition-colors">
                <td className="p-4 border-b border-r bg-white sticky left-0 z-10 group-hover:bg-slate-50/50 border-r-slate-200">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold shadow-sm">
                       {user.name.charAt(0)}
                    </div>
                    <div>
                      <div className="font-semibold text-slate-900 text-sm">{user.name}</div>
                      <div className="text-xs text-slate-500">{user.role}</div>
                    </div>
                  </div>
                </td>
                {weekDays.map((date) => {
                  const assignment = getAssignment(user.id, date);
                  const activeTemplateIds = assignment?.templateIds || [];
                  const hasCustomText = !!assignment?.customText;
                  const isEmpty = activeTemplateIds.length === 0 && !hasCustomText;
                  const isToday = formatDateISO(date) === todayISO;

                  return (
                    <td 
                      key={date.toISOString()} 
                      className={`p-1 border-b border-r cursor-pointer relative transition-all align-top h-24 ${isToday ? 'bg-blue-50/10' : ''}`}
                      onClick={(e) => handleCellClick(e, user.id, date)}
                    >
                      <div className={`w-full h-full min-h-[5rem] rounded-md transition-all flex flex-col overflow-hidden ${isEmpty ? 'border-2 border-dashed border-transparent hover:border-blue-200' : 'bg-white shadow-sm border border-slate-200'}`}>
                        {isEmpty ? (
                           <div className="w-full h-full flex items-center justify-center">
                              <Plus className="w-5 h-5 text-slate-300" />
                           </div>
                        ) : (
                          <>
                            {/* Render Badges/Modules Full Size */}
                            <div className="flex-1 flex flex-col w-full h-full">
                                {activeTemplateIds.map(tid => {
                                    const tpl = templates.find(t => t.id === tid);
                                    if (!tpl) return null;
                                    return (
                                        <div 
                                          key={tid} 
                                          className={`flex-1 flex items-center justify-center px-2 text-xs font-bold ${tpl.color} w-full border-b border-black/10 last:border-0`}
                                          title={tpl.label}
                                        >
                                            <span className="truncate text-center">{tpl.label}</span>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Render Custom Text at bottom if exists */}
                            {hasCustomText && (
                                <div className={`px-1 py-0.5 bg-yellow-50 text-[10px] text-slate-700 leading-tight border-t border-slate-100 text-center truncate ${activeTemplateIds.length === 0 ? 'h-full flex items-center justify-center font-medium text-sm' : ''}`}>
                                    {assignment.customText}
                                </div>
                            )}
                          </>
                        )}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
             {users.length === 0 && (
              <tr>
                <td colSpan={8} className="p-12 text-center text-slate-400">
                  Aucun utilisateur défini. Utilisez le panneau d'administration pour commencer.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Popover Selection Menu */}
      {popover.isOpen && popover.userId && popover.date && (
        <div 
          ref={popoverRef}
          className="fixed bg-white rounded-xl shadow-2xl border border-slate-200 z-50 w-72 p-3 animate-in fade-in zoom-in-95 duration-100 flex flex-col gap-3"
          style={{ top: popover.y, left: popover.x }}
        >
          {/* Custom Text Input */}
          <div className="relative">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Type className="h-4 w-4 text-slate-400" />
             </div>
             <input
                autoFocus
                type="text"
                placeholder="Note personnalisée..."
                className="w-full pl-9 pr-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                value={localText}
                onChange={handleTextChange}
             />
          </div>

          <div className="h-px bg-slate-100"></div>

          {/* Templates Grid */}
          <div className="space-y-1 max-h-60 overflow-y-auto">
             <div className="text-xs font-bold text-slate-400 uppercase px-1 mb-2">Modules (Multi-sélection)</div>
            {templates.map(tpl => {
               const assignment = getAssignment(popover.userId!, popover.date!);
               const isSelected = assignment?.templateIds.includes(tpl.id);

               return (
                  <button
                    key={tpl.id}
                    onClick={() => onToggleTemplate(popover.userId!, popover.date!, tpl.id)}
                    className={`w-full text-left p-2 rounded-lg text-sm font-medium transition-all flex items-center gap-2 group border ${isSelected ? 'bg-blue-50 border-blue-200' : 'border-transparent hover:bg-slate-50'}`}
                  >
                    <div className={`w-4 h-4 rounded flex items-center justify-center border ${isSelected ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                        {isSelected && <Check className="w-3 h-3 text-white" />}
                    </div>
                    {/* Color Circle */}
                    <span className={`w-3 h-3 rounded-full ${tpl.color.split(' ')[0]}`}></span>
                    <span className="flex-1 truncate">{tpl.label}</span>
                  </button>
               );
            })}
          </div>

          <div className="h-px bg-slate-100"></div>

          <button
              onClick={() => {
                  onClear(popover.userId!, popover.date!);
                  setPopover({...popover, isOpen: false});
              }}
              className="w-full text-left p-2 rounded-lg text-sm font-medium text-red-500 hover:bg-red-50 transition-colors flex items-center justify-center gap-2"
          >
            <Eraser className="w-4 h-4" />
            Tout effacer
          </button>
        </div>
      )}
    </div>
  );
};

import { useState, useEffect, useCallback } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { INITIAL_USERS, INITIAL_TEMPLATES } from '../constants';
import { formatDateISO } from '../utils/dateUtils';

export const usePlanner = () => {
  // Load initial state from localStorage or defaults
  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('shiftplan_users');
    return saved ? JSON.parse(saved) : INITIAL_USERS;
  });

  const [templates, setTemplates] = useState<ShiftTemplate[]>(() => {
    const saved = localStorage.getItem('shiftplan_templates');
    return saved ? JSON.parse(saved) : INITIAL_TEMPLATES;
  });

  const [assignments, setAssignments] = useState<Assignment[]>(() => {
    const saved = localStorage.getItem('shiftplan_assignments');
    // Migration helper: if saved data has templateId (old format), convert to templateIds
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.length > 0 && 'templateId' in parsed[0]) {
        return parsed.map((a: any) => ({
          ...a,
          templateIds: a.templateId ? [a.templateId] : [],
          customText: ''
        }));
      }
      return parsed;
    }
    return [];
  });

  // Persistence effects
  useEffect(() => { localStorage.setItem('shiftplan_users', JSON.stringify(users)); }, [users]);
  useEffect(() => { localStorage.setItem('shiftplan_templates', JSON.stringify(templates)); }, [templates]);
  useEffect(() => { localStorage.setItem('shiftplan_assignments', JSON.stringify(assignments)); }, [assignments]);

  // Actions
  const addUser = (user: User) => setUsers([...users, user]);
  const removeUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
    setAssignments(assignments.filter(a => a.userId !== id));
  };
  const updateUser = (updated: User) => {
    setUsers(users.map(u => u.id === updated.id ? updated : u));
  };

  const addTemplate = (tpl: ShiftTemplate) => setTemplates([...templates, tpl]);
  const removeTemplate = (id: string) => {
    setTemplates(templates.filter(t => t.id !== id));
    setAssignments(assignments.map(a => ({
      ...a,
      templateIds: a.templateIds.filter(tid => tid !== id)
    })));
  };
  const updateTemplate = (updated: ShiftTemplate) => {
    setTemplates(templates.map(t => t.id === updated.id ? updated : t));
  };

  // Toggle a specific template for a user/date
  const toggleAssignmentTemplate = (userId: string, date: Date, templateId: string) => {
    const dateStr = formatDateISO(date);
    setAssignments(prev => {
      const existingIndex = prev.findIndex(a => a.userId === userId && a.date === dateStr);

      if (existingIndex >= 0) {
        const existing = prev[existingIndex];
        const hasTemplate = existing.templateIds.includes(templateId);
        let newTemplateIds;

        if (hasTemplate) {
          newTemplateIds = existing.templateIds.filter(id => id !== templateId);
        } else {
          newTemplateIds = [...existing.templateIds, templateId];
        }

        // Clean up if empty? No, keep it if there is custom text.
        if (newTemplateIds.length === 0 && !existing.customText) {
             return prev.filter((_, i) => i !== existingIndex);
        }

        const newAssignments = [...prev];
        newAssignments[existingIndex] = { ...existing, templateIds: newTemplateIds };
        return newAssignments;
      } else {
        return [...prev, { id: crypto.randomUUID(), userId, date: dateStr, templateIds: [templateId], customText: '' }];
      }
    });
  };

  // Set custom text for a user/date
  const updateAssignmentText = (userId: string, date: Date, text: string) => {
    const dateStr = formatDateISO(date);
    setAssignments(prev => {
      const existingIndex = prev.findIndex(a => a.userId === userId && a.date === dateStr);

      if (existingIndex >= 0) {
        const existing = prev[existingIndex];
        if (!text && existing.templateIds.length === 0) {
             return prev.filter((_, i) => i !== existingIndex);
        }
        const newAssignments = [...prev];
        newAssignments[existingIndex] = { ...existing, customText: text };
        return newAssignments;
      } else {
        if (!text) return prev;
        return [...prev, { id: crypto.randomUUID(), userId, date: dateStr, templateIds: [], customText: text }];
      }
    });
  };

  // Replace assignment (used for Paste)
  const replaceAssignment = (userId: string, date: Date, templateIds: string[], customText: string) => {
    const dateStr = formatDateISO(date);
    setAssignments(prev => {
        const existingIndex = prev.findIndex(a => a.userId === userId && a.date === dateStr);

        // If pasting empty data (clearing)
        if (templateIds.length === 0 && !customText) {
            if (existingIndex >= 0) {
                return prev.filter((_, i) => i !== existingIndex);
            }
            return prev;
        }

        if (existingIndex >= 0) {
            const newAssignments = [...prev];
            newAssignments[existingIndex] = { ...newAssignments[existingIndex], templateIds, customText };
            return newAssignments;
        } else {
            return [...prev, { id: crypto.randomUUID(), userId, date: dateStr, templateIds, customText }];
        }
    });
  };

  // Clear everything for a cell
  const clearAssignment = (userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    setAssignments(prev => prev.filter(a => !(a.userId === userId && a.date === dateStr)));
  };

  const getAssignment = useCallback((userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    return assignments.find(a => a.userId === userId && a.date === dateStr);
  }, [assignments]);

  return {
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    getAssignment, toggleAssignmentTemplate, updateAssignmentText, clearAssignment, replaceAssignment
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { getStartOfWeek, addDays, formatDateFr, formatDateISO } from '../utils/dateUtils';
import { ChevronLeft, ChevronRight, Settings, Calendar as CalendarIcon, Check, Eraser, Plus, Type, Copy } from 'lucide-react';

interface CalendarGridProps {
  currentDate: Date;
  onDateChange: (d: Date) => void;
  users: User[];
  templates: ShiftTemplate[];
  getAssignment: (userId: string, date: Date) => Assignment | undefined;
  onToggleTemplate: (userId: string, date: Date, templateId: string) => void;
  onUpdateText: (userId: string, date: Date, text: string) => void;
  onReplace: (userId: string, date: Date, templateIds: string[], customText: string) => void;
  onClear: (userId: string, date: Date) => void;
  onOpenAdmin: () => void;
}

export const CalendarGrid: React.FC<CalendarGridProps> = ({
  currentDate, onDateChange, users, templates, getAssignment, onToggleTemplate, onUpdateText, onReplace, onClear, onOpenAdmin
}) => {
  const startOfWeek = getStartOfWeek(currentDate);
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(startOfWeek, i));
  const todayISO = formatDateISO(new Date());

  // Clipboard State
  const [clipboard, setClipboard] = useState<{templateIds: string[], customText: string} | null>(null);

  // Selection State (which cell is currently focused/selected)
  const [selectedCell, setSelectedCell] = useState<{userId: string, date: Date} | null>(null);

  // Popover state
  const [popover, setPopover] = useState<{
    isOpen: boolean;
    userId: string | null;
    date: Date | null;
    x: number;
    y: number;
  }>({ isOpen: false, userId: null, date: null, x: 0, y: 0 });

  // Local text state for the input in the popover
  const [localText, setLocalText] = useState('');

  const popoverRef = useRef<HTMLDivElement>(null);

  // Load existing text into local state when opening popover
  useEffect(() => {
    if (popover.isOpen && popover.userId && popover.date) {
        const assignment = getAssignment(popover.userId, popover.date);
        setLocalText(assignment?.customText || '');
    }
  }, [popover.isOpen, popover.userId, popover.date, getAssignment]);

  // Close popover when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setPopover({ ...popover, isOpen: false });
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [popover]);

  const handleCellClick = (e: React.MouseEvent, userId: string, date: Date) => {
    // Single click just selects the cell
    setSelectedCell({ userId, date });

    // Explicitly focus the cell (currentTarget is the td)
    (e.currentTarget as HTMLElement).focus();
  };

  const handleCellDoubleClick = (e: React.MouseEvent | React.KeyboardEvent, userId: string, date: Date) => {
    // Double click opens the editor
    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();

    // Adjust position to stay on screen
    let x = rect.left + window.scrollX;
    if (x + 280 > window.innerWidth) {
        x = window.innerWidth - 290;
    }

    setPopover({
      isOpen: true,
      userId,
      date,
      x: x,
      y: rect.bottom + window.scrollY + 5
    });
  };

  const handleKeyDown = (e: React.KeyboardEvent, userId: string, date: Date) => {
    // Ignore key events if popover is open (let popover input handle them)
    if (popover.isOpen) return;

    // Enter -> Open Editor
    if (e.key === 'Enter') {
        e.preventDefault();
        handleCellDoubleClick(e, userId, date);
    }

    // Delete / Backspace -> Clear
    if (e.key === 'Delete' || e.key === 'Backspace') {
        onClear(userId, date);
    }

    // Ctrl+C -> Copy
    if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
        e.preventDefault();
        const assignment = getAssignment(userId, date);
        if (assignment) {
            setClipboard({
                templateIds: assignment.templateIds,
                customText: assignment.customText || ''
            });
            // Could show a toast here
        } else {
            setClipboard(null);
        }
    }

    // Ctrl+V -> Paste
    if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
        e.preventDefault();
        if (clipboard) {
            onReplace(userId, date, clipboard.templateIds, clipboard.customText);
        }
    }
  };

  const handleTextChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setLocalText(e.target.value);
      if (popover.userId && popover.date) {
          onUpdateText(popover.userId, popover.date, e.target.value);
      }
  };

  return (
    <div className="flex flex-col h-full bg-white shadow-sm border rounded-xl overflow-hidden">
      {/* Calendar Header Controls */}
      <div className="flex items-center justify-between p-4 border-b bg-white">
        <div className="flex items-center gap-4">
          <div className="flex bg-slate-100 rounded-lg p-1 border border-slate-200">
            <button 
              onClick={() => onDateChange(addDays(currentDate, -7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronLeft className="w-5 h-5" />
            </button>
            <button 
              onClick={() => onDateChange(new Date())}
              className="px-3 py-1 text-sm font-medium text-slate-600 hover:bg-white hover:shadow-sm rounded-md transition-all"
            >
              Aujourd'hui
            </button>
            <button 
              onClick={() => onDateChange(addDays(currentDate, 7))}
              className="p-1 hover:bg-white hover:shadow-sm rounded-md transition-all text-slate-600"
            >
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
          <h2 className="text-lg font-bold text-slate-800 capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-blue-600" />
            {new Intl.DateTimeFormat('fr-FR', { month: 'long', year: 'numeric' }).format(currentDate)}
          </h2>
          {/* Legend / Help */}
          <div className="hidden lg:flex items-center gap-2 ml-4 px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-xs font-medium border border-blue-100">
            <Copy className="w-3 h-3" />
            <span>Astuce : Double-clic pour éditer, Ctrl+C / Ctrl+V pour copier-coller</span>
          </div>
        </div>

        <button 
          onClick={onOpenAdmin}
          className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white text-sm font-medium rounded-lg hover:bg-slate-700 transition-colors shadow-sm"
        >
          <Settings className="w-4 h-4" />
          <span>Gérer l'équipe & Modèles</span>
        </button>
      </div>

      {/* Main Grid Area */}
      <div className="flex-1 overflow-auto relative">
        <table className="w-full border-collapse min-w-[1000px]">
          <thead className="bg-slate-50 sticky top-0 z-10 shadow-sm">
            <tr>
              <th className="p-4 text-left border-b border-r w-64 bg-slate-50 sticky left-0 z-20">
                <span className="text-xs font-bold text-slate-400 uppercase tracking-wider">Membres</span>
              </th>
              {weekDays.map((date) => {
                const isToday = formatDateISO(date) === todayISO;
                return (
                  <th key={date.toISOString()} className={`p-3 text-center border-b border-r min-w-[120px] ${isToday ? 'bg-blue-50/50' : ''}`}>
                    <div className={`flex flex-col items-center justify-center`}>
                      <span className={`text-xs uppercase font-bold mb-1 ${isToday ? 'text-blue-600' : 'text-slate-400'}`}>
                        {new Intl.DateTimeFormat('fr-FR', { weekday: 'short' }).format(date)}
                      </span>
                      <span className={`text-xl font-light w-8 h-8 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white shadow-md' : 'text-slate-700'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id} className="group hover:bg-slate-50/50 transition-colors">
                <td className="p-4 border-b border-r bg-white sticky left-0 z-10 group-hover:bg-slate-50/50 border-r-slate-200">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold shadow-sm">
                       {user.name.charAt(0)}
                    </div>
                    <div>
                      <div className="font-semibold text-slate-900 text-sm">{user.name}</div>
                      <div className="text-xs text-slate-500">{user.role}</div>
                    </div>
                  </div>
                </td>
                {weekDays.map((date) => {
                  const assignment = getAssignment(user.id, date);
                  const activeTemplateIds = assignment?.templateIds || [];
                  const hasCustomText = !!assignment?.customText;
                  const isEmpty = activeTemplateIds.length === 0 && !hasCustomText;
                  const isToday = formatDateISO(date) === todayISO;
                  const isSelected = selectedCell?.userId === user.id && selectedCell?.date.getTime() === date.getTime();

                  return (
                    <td 
                      key={date.toISOString()} 
                      className={`p-1 border-b border-r cursor-pointer relative transition-all align-top h-24 outline-none focus:bg-blue-50/30 ${isToday ? 'bg-blue-50/10' : ''}`}
                      onClick={(e) => handleCellClick(e, user.id, date)}
                      onDoubleClick={(e) => handleCellDoubleClick(e, user.id, date)}
                      onKeyDown={(e) => handleKeyDown(e, user.id, date)}
                      tabIndex={0} // Make focusable
                    >
                      <div className={`w-full h-full min-h-[5rem] rounded-md transition-all flex flex-col overflow-hidden ${isSelected ? 'ring-2 ring-blue-500 z-10' : ''} ${isEmpty ? 'border-2 border-dashed border-transparent hover:border-blue-200' : 'bg-white shadow-sm border border-slate-200'}`}>
                        {isEmpty ? (
                           <div className="w-full h-full flex items-center justify-center">
                              <Plus className={`w-5 h-5 text-slate-300 ${isSelected ? 'text-blue-400' : ''}`} />
                           </div>
                        ) : (
                          <>
                            {/* Render Badges/Modules Full Size */}
                            <div className="flex-1 flex flex-col w-full h-full">
                                {activeTemplateIds.map(tid => {
                                    const tpl = templates.find(t => t.id === tid);
                                    if (!tpl) return null;
                                    return (
                                        <div 
                                          key={tid} 
                                          className={`flex-1 flex items-center justify-center px-2 text-xs font-bold ${tpl.color} w-full border-b border-black/10 last:border-0`}
                                          title={tpl.label}
                                        >
                                            <span className="truncate text-center">{tpl.label}</span>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Render Custom Text at bottom if exists */}
                            {hasCustomText && (
                                <div className={`px-1 py-0.5 bg-yellow-50 text-[10px] text-slate-700 leading-tight border-t border-slate-100 text-center truncate ${activeTemplateIds.length === 0 ? 'h-full flex items-center justify-center font-medium text-sm' : ''}`}>
                                    {assignment.customText}
                                </div>
                            )}
                          </>
                        )}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
             {users.length === 0 && (
              <tr>
                <td colSpan={8} className="p-12 text-center text-slate-400">
                  Aucun utilisateur défini. Utilisez le panneau d'administration pour commencer.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Popover Selection Menu */}
      {popover.isOpen && popover.userId && popover.date && (
        <div 
          ref={popoverRef}
          className="fixed bg-white rounded-xl shadow-2xl border border-slate-200 z-50 w-72 p-3 animate-in fade-in zoom-in-95 duration-100 flex flex-col gap-3"
          style={{ top: popover.y, left: popover.x }}
        >
          {/* Custom Text Input */}
          <div className="relative">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Type className="h-4 w-4 text-slate-400" />
             </div>
             <input
                autoFocus
                type="text"
                placeholder="Note personnalisée..."
                className="w-full pl-9 pr-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none"
                value={localText}
                onChange={handleTextChange}
             />
          </div>

          <div className="h-px bg-slate-100"></div>

          {/* Templates Grid */}
          <div className="space-y-1 max-h-60 overflow-y-auto">
             <div className="text-xs font-bold text-slate-400 uppercase px-1 mb-2">Modules (Multi-sélection)</div>
            {templates.map(tpl => {
