                    className={`w-full text-left p-2 rounded-lg text-sm font-medium transition-all flex items-center gap-2 group border ${isSelected ? 'bg-blue-50 border-blue-200' : 'border-transparent hover:bg-slate-50'}`}
                  >
                    <div className={`w-4 h-4 rounded flex items-center justify-center border ${isSelected ? 'bg-blue-600 border-blue-600' : 'border-slate-300 bg-white'}`}>
                        {isSelected && <Check className="w-3 h-3 text-white" />}
                    </div>
                    {/* Color Circle */}
                    <span className={`w-3 h-3 rounded-full ${tpl.color.split(' ')[0]}`}></span>
                    <span className="flex-1 truncate">{tpl.label}</span>
                  </button>
               );
            })}
          </div>

          <div className="h-px bg-slate-100"></div>

          <button
              onClick={() => {
                  onClear(popover.userId!, popover.date!);
                  setPopover({...popover, isOpen: false});
              }}
              className="w-full text-left p-2 rounded-lg text-sm font-medium text-red-500 hover:bg-red-50 transition-colors flex items-center justify-center gap-2"
          >
            <Eraser className="w-4 h-4" />
            Tout effacer
          </button>
        </div>
      )}
    </div>
  );
};

