import { useState, useEffect, useCallback, useRef } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { INITIAL_USERS, INITIAL_TEMPLATES } from '../constants';
import { formatDateISO } from '../utils/dateUtils';

// Helper to interact with the Node.js backend
const API_URL = '/api/db';

export const usePlanner = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // State containers
  const [users, setUsers] = useState<User[]>([]);
  const [templates, setTemplates] = useState<ShiftTemplate[]>([]);
  const [assignments, setAssignments] = useState<Assignment[]>([]);

  // Refs to access latest state inside async/interval functions without dependencies issues
  const stateRef = useRef({ users, templates, assignments });

  useEffect(() => {
    stateRef.current = { users, templates, assignments };
  }, [users, templates, assignments]);

  // --- API FUNCTIONS ---

  const fetchData = async () => {
    try {
      const res = await fetch(API_URL);
      if (!res.ok) throw new Error("Erreur serveur");
      const data = await res.json();

      // Update state only if data actually changed (basic check to avoid re-renders)
      // For a real prod app, use deep comparison or a library like React Query.
      // Here we just set it, React handles the diffing.
      setUsers(data.users || []);
      setTemplates(data.templates || []);
      setAssignments(data.assignments || []);
      setLoading(false);
      setError(null);
    } catch (err) {
      console.error("Failed to fetch data:", err);
      // Fallback for first run or offline (optional)
      if (loading) {
         setLoading(false);
         setError("Impossible de se connecter au serveur.");
      }
    }
  };

  const saveData = async (newUsers: User[], newTemplates: ShiftTemplate[], newAssignments: Assignment[]) => {
    try {
      await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          users: newUsers,
          templates: newTemplates,
          assignments: newAssignments
        })
      });
    } catch (err) {
      console.error("Failed to save data:", err);
      setError("Erreur de sauvegarde !");
    }
  };

  // --- INITIALIZATION & POLLING ---

  useEffect(() => {
    // 1. Initial Load
    fetchData();

    // 2. Polling (Check for updates from other colleagues every 2 seconds)
    const intervalId = setInterval(() => {
        // Only fetch if we are not currently dragging/editing? 
        // For simplicity in this version, we fetch always. 
        // In a complex app, we would use WebSockets or check a timestamp first.
        fetchData();
    }, 2000);

    return () => clearInterval(intervalId);
  }, []);

  // --- ACTIONS (Optimistic Update + Save) ---

  const addUser = (user: User) => {
    const nextUsers = [...users, user];
    setUsers(nextUsers);
    saveData(nextUsers, templates, assignments);
  };

  const removeUser = (id: string) => {
    const nextUsers = users.filter(u => u.id !== id);
    const nextAssignments = assignments.filter(a => a.userId !== id);
    setUsers(nextUsers);
    setAssignments(nextAssignments);
    saveData(nextUsers, templates, nextAssignments);
  };

  // We don't implement updateUser fully in UI yet, but logic is here
  const updateUser = (updated: User) => {
      const nextUsers = users.map(u => u.id === updated.id ? updated : u);
      setUsers(nextUsers);
      saveData(nextUsers, templates, assignments);
  };

  const addTemplate = (tpl: ShiftTemplate) => {
    const nextTemplates = [...templates, tpl];
    setTemplates(nextTemplates);
    saveData(users, nextTemplates, assignments);
  };

  const removeTemplate = (id: string) => {
    const nextTemplates = templates.filter(t => t.id !== id);
    const nextAssignments = assignments.map(a => ({
      ...a,
      templateIds: a.templateIds.filter(tid => tid !== id)
    }));
    setTemplates(nextTemplates);
    setAssignments(nextAssignments);
    saveData(users, nextTemplates, nextAssignments);
  };

  const updateTemplate = (updated: ShiftTemplate) => {
      const nextTemplates = templates.map(t => t.id === updated.id ? updated : t);
      setTemplates(nextTemplates);
      saveData(users, nextTemplates, assignments);
  };

  const toggleAssignmentTemplate = (userId: string, date: Date, templateId: string) => {
    const dateStr = formatDateISO(date);

    // Calculate new state based on CURRENT state variable (optimistic)
    const prevAssignments = assignments; 
    let nextAssignments = [...prevAssignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (existingIndex >= 0) {
      const existing = nextAssignments[existingIndex];
      const hasTemplate = existing.templateIds.includes(templateId);
      let newTemplateIds;

      if (hasTemplate) {
        newTemplateIds = existing.templateIds.filter(id => id !== templateId);
      } else {
        newTemplateIds = [...existing.templateIds, templateId];
      }

      if (newTemplateIds.length === 0 && !existing.customText) {
           nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
      } else {
           nextAssignments[existingIndex] = { ...existing, templateIds: newTemplateIds };
      }
    } else {
      nextAssignments.push({ id: crypto.randomUUID(), userId, date: dateStr, templateIds: [templateId], customText: '' });
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments);
  };

  const updateAssignmentText = (userId: string, date: Date, text: string) => {
    const dateStr = formatDateISO(date);
    const prevAssignments = assignments;
    let nextAssignments = [...prevAssignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (existingIndex >= 0) {
      const existing = nextAssignments[existingIndex];
      if (!text && existing.templateIds.length === 0) {
           nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
      } else {
           nextAssignments[existingIndex] = { ...existing, customText: text };
      }
    } else {
      if (text) {
          nextAssignments.push({ id: crypto.randomUUID(), userId, date: dateStr, templateIds: [], customText: text });
      }
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments);
  };

  const replaceAssignment = (userId: string, date: Date, templateIds: string[], customText: string) => {
    const dateStr = formatDateISO(date);
    const prevAssignments = assignments;
    let nextAssignments = [...prevAssignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (templateIds.length === 0 && !customText) {
        if (existingIndex >= 0) {
            nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
        }
    } else {
        if (existingIndex >= 0) {
            nextAssignments[existingIndex] = { ...nextAssignments[existingIndex], templateIds, customText };
        } else {
            nextAssignments.push({ id: crypto.randomUUID(), userId, date: dateStr, templateIds, customText });
        }
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments);
  };

  const clearAssignment = (userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    const nextAssignments = assignments.filter(a => !(a.userId === userId && a.date === dateStr));
    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments);
  };

  const getAssignment = useCallback((userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    return assignments.find(a => a.userId === userId && a.date === dateStr);
  }, [assignments]);

  return {
    loading, error,
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    getAssignment, toggleAssignmentTemplate, updateAssignmentText, clearAssignment, replaceAssignment
  };
};

import React, { useState } from 'react';
import { CalendarGrid } from './components/CalendarGrid';
import { AdminPanel } from './components/AdminPanel';
import { usePlanner } from './hooks/usePlanner';
import { Loader2, AlertCircle } from 'lucide-react';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
