  return (
    <div className="h-full flex flex-col bg-slate-100">
      {/* Top Navigation Bar */}
      <nav className="bg-white border-b px-6 py-3 flex items-center justify-between shadow-sm z-20">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
            <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">ShiftPlan Pro</h1>
            <p className="text-xs text-slate-500 font-medium">
                {error ? <span className="text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3"/> Déconnecté</span> : 'En ligne - Synchronisé'}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="text-sm text-slate-500 hidden md:block">
              Bienvenue, <strong>Admin</strong>
           </div>
           <div className="w-8 h-8 rounded-full bg-slate-200 border-2 border-white shadow-sm overflow-hidden">
             <img src="https://picsum.photos/100/100" alt="Avatar" className="w-full h-full object-cover" />
           </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col">
        {error && (
            <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-2 rounded-lg mb-4 text-sm flex items-center gap-2">
                <AlertCircle className="w-4 h-4" />
                Attention : {error}. Les modifications ne seront pas sauvegardées sur le serveur.
            </div>
        )}

        <div className="flex-1 h-full min-h-0">
          <CalendarGrid 
            currentDate={currentDate}
            onDateChange={setCurrentDate}
            users={users}
            templates={templates}
            getAssignment={getAssignment}
            onToggleTemplate={toggleAssignmentTemplate}
            onUpdateText={updateAssignmentText}
            onReplace={replaceAssignment}
            onClear={clearAssignment}
            onOpenAdmin={() => setIsAdminOpen(true)}
          />
        </div>
      </main>

      {/* Admin Modal */}
      {isAdminOpen && (
        <AdminPanel 
          users={users}
          templates={templates}
          onAddUser={addUser}
          onRemoveUser={removeUser}
          onAddTemplate={addTemplate}
          onRemoveTemplate={removeTemplate}
          onClose={() => setIsAdminOpen(false)}
        />
      )}
    </div>
  );
};

export default App;

