export const DisplaySettings: React.FC<DisplaySettingsProps> = ({
  showWeekends, onToggleWeekends, backgroundImage, onSetBackgroundImage, bgOpacity, onSetBgOpacity, onClose
}) => {
  const [customUrl, setCustomUrl] = useState('');
  const [uploadError, setUploadError] = useState<string | null>(null);

  const handleCustomUrlSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (customUrl) {
      onSetBackgroundImage(customUrl);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 2 * 1024 * 1024) { // Limit to 2MB
        setUploadError("L'image est trop lourde (Max 2Mo)");
        return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
        const result = reader.result as string;
        try {
            onSetBackgroundImage(result);
            setUploadError(null);
        } catch (err) {
            setUploadError("Erreur lors de la sauvegarde. L'image est peut-être trop grande pour le stockage local.");
        }
    };
    reader.onerror = () => {
        setUploadError("Erreur lors de la lecture du fichier.");
    };
    reader.readAsDataURL(file);
  };

