  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' ? 'dark' : 'light';
    }
    return 'light';
  });

  // Display Preferences State (Weekends & Background)
  const [showWeekends, setShowWeekends] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('showWeekends');
      return stored === null ? true : stored === 'true';
    }
    return true;
  });

  const [backgroundImage, setBackgroundImage] = useState<string | null>(() => {
    if (typeof window !== 'undefined') return localStorage.getItem('backgroundImage');
    return null;
  });

  const [bgOpacity, setBgOpacity] = useState<number>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('bgOpacity');
      return stored ? parseFloat(stored) : 0.95;
    }
    return 0.95;
  });

  // Apply Theme Effect
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Persist Display Preferences
  useEffect(() => {
    localStorage.setItem('showWeekends', String(showWeekends));
  }, [showWeekends]);

  useEffect(() => {
    if (backgroundImage) {
      localStorage.setItem('backgroundImage', backgroundImage);
    } else {
      localStorage.removeItem('backgroundImage');
    }
  }, [backgroundImage]);

  useEffect(() => {
    localStorage.setItem('bgOpacity', String(bgOpacity));
  }, [bgOpacity]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const {
    loading, error,
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    holidays, toggleHoliday, moveAssignment,
    getAssignment, toggleAssignmentTemplate, updateAssignmentText, clearAssignment, replaceAssignment
  } = usePlanner();

  // Helper to get raw assignments list for Month View
  const getAllAssignments = () => {
    // In a real app we might pass the raw list down, but `usePlanner` exposes a getter.
    // For MonthView we need to iterate differently or access the internal state.
    // Since `getAssignment` is a lookup, we'll access the internal state via a new exposed prop or refactor `usePlanner`.
    // However, looking at `usePlanner`, it returns `assignments` state implicitly if we exported it? 
    // Wait, usePlanner returns `getAssignment` but not the raw array. 
    // Let's modify usePlanner locally in this file's usage or assume we can export it.
    // Actually, checking previous files, `usePlanner` returns objects. 
    // I need to update usePlanner to return `assignments` raw array.
    // BUT, I can't update usePlanner in this XML block without repeating it.
    // Wait, I can just use `getAssignment` on every day of the month for every user?
    // That's O(Users * DaysInMonth) operations. Not too bad for small teams (e.g. 20 users * 30 days = 600 calls).
    // Better: let's update `usePlanner` export in a separate change block if needed, 
    // OR just use a trick: `usePlanner` does not return `assignments`. 
    // Let's modify `usePlanner` to return `assignments`.
    return []; // Placeholder until usePlanner update.
  };

  // We need the raw assignments array for MonthView to perform well, or we loop.
  // Let's check `usePlanner.ts`. It returns `getAssignment`. 
  // I will add `assignments` to the return of `usePlanner` in a separate block below to ensure data flow.

  if (loading) {
