import React, { useState } from 'react';
import { X, Image as ImageIcon, Layout, Check, RotateCcw, Upload, AlertCircle, Globe } from 'lucide-react';

interface DisplaySettingsProps {
  showWeekends: boolean;
  onToggleWeekends: (show: boolean) => void;
  backgroundImage: string | null;
  onSetBackgroundImage: (url: string | null) => void;
  bgOpacity: number;
  onSetBgOpacity: (opacity: number) => void;
  onClose: () => void;
}

const PRESET_BACKGROUNDS = [
  { name: 'Bureau Moderne', url: 'https://images.unsplash.com/photo-1497366216548-37526070297c?auto=format&fit=crop&q=80&w=1920' },
  { name: 'Nature Calme', url: 'https://images.unsplash.com/photo-1472214103451-9374bd1c798e?auto=format&fit=crop&q=80&w=1920' },
  { name: 'Abstrait Bleu', url: 'https://images.unsplash.com/photo-1557683316-973673baf926?auto=format&fit=crop&q=80&w=1920' },
  { name: 'Architecture', url: 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80&w=1920' },
];

export const DisplaySettings: React.FC<DisplaySettingsProps> = ({
  showWeekends, onToggleWeekends, backgroundImage, onSetBackgroundImage, bgOpacity, onSetBgOpacity, onClose
}) => {
  const [customUrl, setCustomUrl] = useState('');
  const [uploadError, setUploadError] = useState<string | null>(null);

  const handleCustomUrlSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (customUrl) {
      onSetBackgroundImage(customUrl);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 2 * 1024 * 1024) { // Limit to 2MB
        setUploadError("L'image est trop lourde (Max 2Mo)");
        return;
    }

    const reader = new FileReader();
    reader.onloadend = () => {
        const result = reader.result as string;
        try {
            onSetBackgroundImage(result);
            setUploadError(null);
        } catch (err) {
            setUploadError("Erreur lors de la sauvegarde.");
        }
    };
    reader.onerror = () => {
        setUploadError("Erreur lors de la lecture du fichier.");
    };
    reader.readAsDataURL(file);
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 w-full max-w-md rounded-xl shadow-2xl flex flex-col animate-in fade-in zoom-in duration-200 transition-colors">
        <div className="p-4 border-b dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-800/50 rounded-t-xl">
          <h2 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
            <Layout className="w-5 h-5 text-blue-600" />
            Personnalisation
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-5 h-5 text-slate-500 dark:text-slate-400" />
          </button>
        </div>

        <div className="p-6 space-y-6">
          {/* Weekend Toggle */}
          <div className="space-y-3">
            <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Calendrier (Local)</h3>
            <label className="flex items-center justify-between p-3 border dark:border-slate-700 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors">
              <span className="text-slate-700 dark:text-slate-200 font-medium">Afficher les week-ends</span>
              <div className={`w-12 h-6 rounded-full p-1 transition-colors duration-200 ease-in-out ${showWeekends ? 'bg-blue-600' : 'bg-slate-300 dark:bg-slate-600'}`}>
                <div className={`bg-white w-4 h-4 rounded-full shadow-sm transform transition-transform duration-200 ease-in-out ${showWeekends ? 'translate-x-6' : 'translate-x-0'}`} />
              </div>
              <input 
                type="checkbox" 
                className="hidden" 
                checked={showWeekends} 
                onChange={(e) => onToggleWeekends(e.target.checked)} 
              />
            </label>
          </div>

          <div className="h-px bg-slate-100 dark:bg-slate-700"></div>

          {/* Background Settings */}
          <div className="space-y-4">
            <div className="flex items-center justify-between">
               <div className="flex items-center gap-2">
                 <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Arrière-plan</h3>
                 <span className="flex items-center gap-1 text-[10px] bg-blue-100 dark:bg-blue-900 text-blue-600 dark:text-blue-300 px-1.5 py-0.5 rounded font-bold uppercase"><Globe className="w-3 h-3"/> Partagé</span>
               </div>
               {backgroundImage && (
                 <button onClick={() => onSetBackgroundImage(null)} className="text-xs text-red-500 hover:underline flex items-center gap-1">
                   <RotateCcw className="w-3 h-3"/> Réinitialiser
                 </button>
               )}
            </div>

            {/* Opacity Slider */}
            {backgroundImage && (
              <div className="bg-slate-50 dark:bg-slate-900 p-3 rounded-lg border dark:border-slate-700">
                <div className="flex justify-between mb-2">
                  <span className="text-xs font-medium text-slate-600 dark:text-slate-400">Opacité du contenu</span>
                  <span className="text-xs font-bold text-blue-600">{Math.round(bgOpacity * 100)}%</span>
                </div>
                <input 
                  type="range" 
                  min="0.5" 
                  max="1" 
                  step="0.05" 
                  value={bgOpacity}
                  onChange={(e) => onSetBgOpacity(parseFloat(e.target.value))}
                  className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
                />
              </div>
            )}

            {/* Custom Uploads */}
            <div className="space-y-2">
                <label className="flex items-center justify-center w-full px-4 py-2 bg-white dark:bg-slate-800 border-2 border-dashed border-slate-300 dark:border-slate-600 rounded-lg cursor-pointer hover:border-blue-500 hover:bg-blue-50 dark:hover:bg-slate-700 transition-colors gap-2 text-sm font-medium text-slate-600 dark:text-slate-300">
                    <Upload className="w-4 h-4" />
                    Importer une image (Max 2Mo)
                    <input type="file" className="hidden" accept="image/png, image/jpeg, image/webp" onChange={handleFileUpload} />
                </label>
                {uploadError && (
                    <div className="text-xs text-red-500 flex items-center gap-1">
                        <AlertCircle className="w-3 h-3" /> {uploadError}
                    </div>
                )}
            </div>

            <div className="flex items-center gap-2 my-2">
                <div className="h-px bg-slate-200 dark:bg-slate-700 flex-1"></div>
                <span className="text-xs text-slate-400 uppercase">Ou via URL</span>
                <div className="h-px bg-slate-200 dark:bg-slate-700 flex-1"></div>
            </div>

            {/* URL Input */}
            <form onSubmit={handleCustomUrlSubmit} className="flex gap-2">
              <div className="relative flex-1">
                 <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <ImageIcon className="h-4 w-4 text-slate-400" />
                 </div>
                 <input 
                   type="text" 
                   placeholder="https://..." 
                   className="w-full pl-9 pr-3 py-2 text-sm border dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 bg-white dark:bg-slate-800 dark:text-white"
                   value={customUrl}
                   onChange={(e) => setCustomUrl(e.target.value)}
                 />
              </div>
              <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white px-3 rounded-lg font-medium text-sm">OK</button>
            </form>

            {/* Presets */}
            <div className="grid grid-cols-2 gap-2 mt-4">
               {PRESET_BACKGROUNDS.map((bg) => (
                 <button
                   key={bg.name}
                   onClick={() => onSetBackgroundImage(bg.url)}
                   className={`relative h-20 rounded-lg overflow-hidden group border-2 transition-all ${backgroundImage === bg.url ? 'border-blue-500 ring-2 ring-blue-500/30' : 'border-transparent hover:border-blue-300'}`}
                 >
                   <img src={bg.url} alt={bg.name} className="w-full h-full object-cover" />
                   <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                      <span className="text-white text-xs font-bold">{bg.name}</span>
                   </div>
                   {backgroundImage === bg.url && (
                     <div className="absolute top-1 right-1 bg-blue-500 rounded-full p-0.5">
                       <Check className="w-3 h-3 text-white" />
                     </div>
                   )}
                 </button>
               ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { getStartOfMonth, getEndOfMonth, getStartOfWeek, addDays, formatDateISO } from '../utils/dateUtils';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon, Settings } from 'lucide-react';

interface MonthViewProps {
  currentDate: Date;
  onDateChange: (d: Date) => void;
  users: User[];
  templates: ShiftTemplate[];
  assignments: Assignment[]; 
  holidays: string[];
  showWeekends: boolean;
  onOpenAdmin: () => void;
  onDayClick: (d: Date) => void; // New interaction
}

export const MonthView: React.FC<MonthViewProps> = ({
  currentDate, onDateChange, users, templates, assignments, holidays, showWeekends, onOpenAdmin, onDayClick
}) => {
  const startMonth = getStartOfMonth(currentDate);
  const endMonth = getEndOfMonth(currentDate);
  const startDate = getStartOfWeek(startMonth);
  const endDate = addDays(getStartOfWeek(endMonth), 6);

  const todayISO = formatDateISO(new Date());

  // Generate calendar grid
  const calendarDays = [];
  let day = startDate;
  while (day <= endDate) {
    calendarDays.push(day);
    day = addDays(day, 1);
  }

  const daysToShow = showWeekends 
    ? calendarDays 
    : calendarDays.filter(d => d.getDay() !== 0 && d.getDay() !== 6);

  const gridCols = showWeekends ? 'grid-cols-7' : 'grid-cols-5';
  const weekDayNames = showWeekends 
    ? ['Lun', 'Mar', 'Mer', 'Jeu', 'Ven', 'Sam', 'Dim']
    : ['Lun', 'Mar', 'Mer', 'Jeu', 'Ven'];

  return (
    <div className="flex flex-col h-full bg-white/95 dark:bg-slate-800/95 shadow-sm border dark:border-slate-700 rounded-xl overflow-hidden transition-colors backdrop-blur-sm">
      <div className="flex items-center justify-between p-4 border-b dark:border-slate-700 bg-white/50 dark:bg-slate-800/50 transition-colors">
        <div className="flex items-center gap-4">
          <div className="flex bg-slate-100 dark:bg-slate-700 rounded-lg p-1 border border-slate-200 dark:border-slate-600">
            <button onClick={() => onDateChange(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} className="p-1 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all text-slate-600 dark:text-slate-300"><ChevronLeft className="w-5 h-5" /></button>
            <button onClick={() => onDateChange(new Date())} className="px-3 py-1 text-sm font-medium text-slate-600 dark:text-slate-200 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all">Aujourd'hui</button>
            <button onClick={() => onDateChange(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-1 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all text-slate-600 dark:text-slate-300"><ChevronRight className="w-5 h-5" /></button>
          </div>
          <h2 className="text-lg font-bold text-slate-800 dark:text-white capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-blue-600 dark:text-blue-400" />
            {new Intl.DateTimeFormat('fr-FR', { month: 'long', year: 'numeric' }).format(currentDate)}
          </h2>
        </div>
        <button onClick={onOpenAdmin} className="flex items-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-700 text-white text-sm font-medium rounded-lg hover:bg-slate-700 dark:hover:bg-slate-600 transition-colors shadow-sm">
          <Settings className="w-4 h-4" />
          <span>Gérer l'équipe</span>
        </button>
      </div>

      <div className="flex-1 overflow-auto bg-slate-50 dark:bg-slate-900/50 p-4">
        <div className={`grid ${gridCols} gap-4 h-full min-h-[600px] auto-rows-fr`}>
          {/* Headers */}
          {weekDayNames.map(dayName => (
            <div key={dayName} className="text-center font-bold text-slate-500 dark:text-slate-400 uppercase text-xs py-2">
              {dayName}
            </div>
          ))}

          {/* Days */}
          {daysToShow.map(date => {
            const dateISO = formatDateISO(date);
            const isToday = dateISO === todayISO;
            const isCurrentMonth = date.getMonth() === currentDate.getMonth();
            const isHoliday = holidays.includes(dateISO);

            // Find assignments for this day
            const dayAssignments = assignments.filter(a => a.date === dateISO && (a.templateIds.length > 0 || a.customText));

            return (
              <div 
                key={dateISO} 
                onClick={() => onDayClick(date)}
                className={`min-h-[100px] bg-white dark:bg-slate-800 rounded-lg border p-2 flex flex-col gap-1 transition-all cursor-pointer hover:border-blue-400 dark:hover:border-blue-600 hover:shadow-md
                  ${isToday ? 'ring-2 ring-blue-500 shadow-md' : 'border-slate-200 dark:border-slate-700'} 
                  ${!isCurrentMonth ? 'opacity-50 grayscale bg-slate-50 dark:bg-slate-900' : ''}
                  ${isHoliday ? 'bg-red-50/50 dark:bg-red-900/10' : ''}
                `}
              >
                <div className="flex justify-between items-start pointer-events-none">
                  <span className={`text-sm font-bold w-6 h-6 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white' : isHoliday ? 'text-red-600' : 'text-slate-700 dark:text-slate-200'}`}>
                    {date.getDate()}
                  </span>
                  {isHoliday && <span className="text-[10px] font-bold text-red-500 uppercase">Férié</span>}
                </div>

                <div className="flex-1 overflow-y-auto space-y-1 mt-1 custom-scrollbar pointer-events-none">
                  {dayAssignments.map(assign => {
                    const user = users.find(u => u.id === assign.userId);
                    if (!user) return null;

                    return (
                      <div key={assign.id} className="flex items-center gap-1.5 text-xs bg-slate-50 dark:bg-slate-700/50 rounded px-1.5 py-1 border border-slate-100 dark:border-slate-600">
                         <div className="w-1.5 h-1.5 rounded-full shrink-0 bg-slate-400" 
                              style={{ 
                                backgroundColor: assign.templateIds.length > 0 
                                  ? undefined 
                                  : undefined 
                              }}>
                              {assign.templateIds.length > 0 && (
                                <div className={`w-full h-full rounded-full ${templates.find(t => t.id === assign.templateIds[0])?.color.split(' ')[0] || 'bg-slate-400'}`}></div>
                              )}
                              {assign.templateIds.length === 0 && <div className="w-full h-full rounded-full bg-yellow-400"></div>}
                         </div>
                         <span className="truncate font-medium text-slate-700 dark:text-slate-300 flex-1">{user.name.split(' ')[0]}</span>
                      </div>
                    );
                  })}
                  {dayAssignments.length === 0 && isCurrentMonth && !isHoliday && (
                      <div className="text-[10px] text-slate-300 dark:text-slate-600 text-center mt-2 italic opacity-50">. . .</div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CalendarGrid } from './components/CalendarGrid';
import { AdminPanel } from './components/AdminPanel';
import { DisplaySettings } from './components/DisplaySettings';
import { usePlanner } from './hooks/usePlanner';
import { Loader2, AlertCircle, Moon, Sun, Layout } from 'lucide-react';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isDisplaySettingsOpen, setIsDisplaySettingsOpen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark' ? 'dark' : 'light';
    }
    return 'light';
  });

  // Display Preferences State (Weekends only - Background is now shared)
  const [showWeekends, setShowWeekends] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('showWeekends');
      return stored === null ? true : stored === 'true';
    }
    return true;
  });

  const [bgOpacity, setBgOpacity] = useState<number>(() => {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('bgOpacity');
      return stored ? parseFloat(stored) : 0.95;
    }
    return 0.95;
  });

  // Apply Theme Effect
  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Persist Local Display Preferences
  useEffect(() => {
    localStorage.setItem('showWeekends', String(showWeekends));
  }, [showWeekends]);

  useEffect(() => {
    localStorage.setItem('bgOpacity', String(bgOpacity));
  }, [bgOpacity]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const {
    loading, error,
    users, addUser, removeUser, updateUser,
    templates, addTemplate, removeTemplate, updateTemplate,
    holidays, toggleHoliday, moveAssignment,
    getAssignment, 
    backgroundImage, setBackgroundImage, // Shared background state
    toggleAssignmentTemplate, updateAssignmentText, clearAssignment, replaceAssignment
  } = usePlanner();

  if (loading) {
    return (
      <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-100 dark:bg-slate-900 text-slate-500 dark:text-slate-400 gap-4">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600" />
        <p className="font-medium">Chargement du planning partagé...</p>
      </div>
    );
  }

  return (
    <div 
      className="h-full flex flex-col bg-slate-100 dark:bg-slate-950 transition-colors duration-200 relative"
      style={backgroundImage ? {
        backgroundImage: `url(${backgroundImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat'
      } : {}}
    >
      {/* Background Overlay to ensure readability if image is set */}
      {backgroundImage && (
        <div 
          className="absolute inset-0 z-0 bg-slate-100 dark:bg-slate-950 transition-opacity duration-200 pointer-events-none"
          style={{ opacity: bgOpacity }}
        ></div>
      )}

      {/* Top Navigation Bar */}
      <nav className="bg-white/90 dark:bg-slate-900/90 border-b dark:border-slate-800 px-6 py-3 flex items-center justify-between shadow-sm z-20 transition-colors backdrop-blur-md">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/20">
            <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 dark:text-white leading-tight">ShiftPlan Pro</h1>
            <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">
                {error ? <span className="text-red-500 flex items-center gap-1"><AlertCircle className="w-3 h-3"/> Déconnecté</span> : 'En ligne - Synchronisé'}
            </p>
          </div>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
           {/* Display Settings Toggle */}
           <button 
             onClick={() => setIsDisplaySettingsOpen(true)}
             className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
             title="Personnalisation"
           >
             <Layout className="w-5 h-5" />
           </button>

           {/* Dark Mode Toggle */}
           <button 
             onClick={toggleTheme}
             className="p-2 rounded-full text-slate-500 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800 transition-colors"
             title={theme === 'dark' ? "Passer en mode clair" : "Passer en mode sombre"}
           >
             {theme === 'dark' ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
           </button>

           <div className="h-6 w-px bg-slate-200 dark:bg-slate-700 mx-1 hidden md:block"></div>

           <div className="text-sm text-slate-500 dark:text-slate-400 hidden md:block">
              Bienvenue, <strong>Admin</strong>
           </div>
           <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 border-2 border-white dark:border-slate-600 shadow-sm overflow-hidden hidden md:block">
             <img src="https://picsum.photos/100/100" alt="Avatar" className="w-full h-full object-cover" />
           </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col z-10 relative">
        {error && (
            <div className="bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-300 px-4 py-2 rounded-lg mb-4 text-sm flex items-center gap-2">
                <AlertCircle className="w-4 h-4" />
                Attention : {error}. Les modifications ne seront pas sauvegardées sur le serveur.
            </div>
        )}

        <div className="flex-1 h-full min-h-0">
          <CalendarGrid 
              currentDate={currentDate}
              onDateChange={setCurrentDate}
              users={users}
              templates={templates}
              holidays={holidays}
              showWeekends={showWeekends}
              getAssignment={getAssignment}
              onToggleTemplate={toggleAssignmentTemplate}
              onUpdateText={updateAssignmentText}
              onReplace={replaceAssignment}
              onClear={clearAssignment}
              onMoveAssignment={moveAssignment}
              onToggleHoliday={toggleHoliday}
              onOpenAdmin={() => setIsAdminOpen(true)}
          />
        </div>
      </main>

      {/* Admin Modal */}
      {isAdminOpen && (
        <AdminPanel 
          users={users}
          templates={templates}
          onAddUser={addUser}
          onRemoveUser={removeUser}
          onUpdateUser={updateUser}
          onAddTemplate={addTemplate}
          onRemoveTemplate={removeTemplate}
          onUpdateTemplate={updateTemplate}
          onClose={() => setIsAdminOpen(false)}
        />
      )}

      {/* Display Settings Modal */}
      {isDisplaySettingsOpen && (
        <DisplaySettings
          showWeekends={showWeekends}
          onToggleWeekends={setShowWeekends}
          backgroundImage={backgroundImage}
          onSetBackgroundImage={setBackgroundImage}
          bgOpacity={bgOpacity}
          onSetBgOpacity={setBgOpacity}
          onClose={() => setIsDisplaySettingsOpen(false)}
        />
      )}
    </div>
  );
};

export default App;

import { useState, useEffect, useCallback, useRef } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { formatDateISO } from '../utils/dateUtils';
import { generateId } from '../utils/idUtils';

// Helper to interact with the Node.js backend
const API_URL = '/api/db';

export const usePlanner = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // State containers
  const [users, setUsers] = useState<User[]>([]);
  const [templates, setTemplates] = useState<ShiftTemplate[]>([]);
  const [assignments, setAssignments] = useState<Assignment[]>([]);
  const [holidays, setHolidays] = useState<string[]>([]);

  // Shared settings
  const [backgroundImage, setSharedBackgroundImage] = useState<string | null>(null);

  // Ref to track saving state to prevent race conditions with polling
  const isSaving = useRef(false);

  // Refs to access latest state inside async/interval functions without dependencies issues
  const stateRef = useRef({ users, templates, assignments, holidays, backgroundImage });

  useEffect(() => {
    stateRef.current = { users, templates, assignments, holidays, backgroundImage };
  }, [users, templates, assignments, holidays, backgroundImage]);

  // --- API FUNCTIONS ---

  const fetchData = async () => {
    // SECURITY: If we are currently saving, DO NOT fetch to avoid overwriting local changes with stale server data
    if (isSaving.current) return;

    try {
      const res = await fetch(API_URL);
      if (!res.ok) throw new Error("Erreur serveur");
      const data = await res.json();

      setUsers(data.users || []);
      setTemplates(data.templates || []);
      setAssignments(data.assignments || []);
      setHolidays(data.holidays || []);
      setSharedBackgroundImage(data.backgroundImage || null);

      setLoading(false);
      setError(null);
    } catch (err) {
      console.error("Failed to fetch data:", err);
      if (loading) {
         // Keep existing data if we fail after first load, otherwise init empty
         if (users.length === 0) {
             setUsers([]);
             setTemplates([]);
             setAssignments([]);
             setHolidays([]);
         }
         setLoading(false);
         setError("Mode hors ligne (Serveur non détecté).");
      }
    }
  };

  const saveData = async (
      newUsers: User[], 
      newTemplates: ShiftTemplate[], 
      newAssignments: Assignment[], 
      newHolidays: string[],
      newBackgroundImage: string | null
  ) => {
    isSaving.current = true;

    try {
      await fetch(API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          users: newUsers,
          templates: newTemplates,
          assignments: newAssignments,
          holidays: newHolidays,
          backgroundImage: newBackgroundImage
        })
      });
      setError(null);
    } catch (err) {
      console.error("Failed to save data:", err);
      setError("Erreur de sauvegarde !");
    } finally {
      // Small delay to ensure the server file write completes before we allow polling again
      setTimeout(() => {
        isSaving.current = false;
      }, 1000);
    }
  };

  // --- INITIALIZATION & POLLING ---

  useEffect(() => {
    fetchData();
    const intervalId = setInterval(() => {
        fetchData();
    }, 2000); 

    return () => clearInterval(intervalId);
  }, []);

  // --- ACTIONS ---

  const addUser = (user: User) => {
    const nextUsers = [...users, user];
    setUsers(nextUsers);
    saveData(nextUsers, templates, assignments, holidays, backgroundImage);
  };

  const removeUser = (id: string) => {
    const nextUsers = users.filter(u => u.id !== id);
    const nextAssignments = assignments.filter(a => a.userId !== id);
    setUsers(nextUsers);
    setAssignments(nextAssignments);
    saveData(nextUsers, templates, nextAssignments, holidays, backgroundImage);
  };

  const updateUser = (updated: User) => {
      const nextUsers = users.map(u => u.id === updated.id ? updated : u);
      setUsers(nextUsers);
      saveData(nextUsers, templates, assignments, holidays, backgroundImage);
  };

  const reorderUser = (id: string, direction: 'up' | 'down') => {
    const index = users.findIndex(u => u.id === id);
    if (index === -1) return;
    if (direction === 'up' && index === 0) return;
    if (direction === 'down' && index === users.length - 1) return;

    const newUsers = [...users];
    const swapIndex = direction === 'up' ? index - 1 : index + 1;

    // Swap elements
    [newUsers[index], newUsers[swapIndex]] = [newUsers[swapIndex], newUsers[index]];

    setUsers(newUsers);
    saveData(newUsers, templates, assignments, holidays, backgroundImage);
  };

  const addTemplate = (tpl: ShiftTemplate) => {
    const nextTemplates = [...templates, tpl];
    setTemplates(nextTemplates);
    saveData(users, nextTemplates, assignments, holidays, backgroundImage);
  };

  const removeTemplate = (id: string) => {
    const nextTemplates = templates.filter(t => t.id !== id);
    const nextAssignments = assignments.map(a => ({
      ...a,
      templateIds: a.templateIds.filter(tid => tid !== id)
    }));
    setTemplates(nextTemplates);
    setAssignments(nextAssignments);
    saveData(users, nextTemplates, nextAssignments, holidays, backgroundImage);
  };

  const updateTemplate = (updated: ShiftTemplate) => {
      const nextTemplates = templates.map(t => t.id === updated.id ? updated : t);
      setTemplates(nextTemplates);
      saveData(users, nextTemplates, assignments, holidays, backgroundImage);
  };

  const toggleAssignmentTemplate = (userId: string, date: Date, templateId: string) => {
    const dateStr = formatDateISO(date);
    let nextAssignments = [...assignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (existingIndex >= 0) {
      const existing = nextAssignments[existingIndex];
      const hasTemplate = existing.templateIds.includes(templateId);
      let newTemplateIds;

      if (hasTemplate) {
        newTemplateIds = existing.templateIds.filter(id => id !== templateId);
      } else {
        newTemplateIds = [...existing.templateIds, templateId];
      }

      if (newTemplateIds.length === 0 && !existing.customText) {
           nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
      } else {
           nextAssignments[existingIndex] = { ...existing, templateIds: newTemplateIds };
      }
    } else {
      nextAssignments.push({ id: generateId(), userId, date: dateStr, templateIds: [templateId], customText: '' });
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments, holidays, backgroundImage);
  };

  const updateAssignmentText = (userId: string, date: Date, text: string) => {
    const dateStr = formatDateISO(date);
    let nextAssignments = [...assignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (existingIndex >= 0) {
      const existing = nextAssignments[existingIndex];
      if (!text && existing.templateIds.length === 0) {
           nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
      } else {
           nextAssignments[existingIndex] = { ...existing, customText: text };
      }
    } else {
      if (text) {
          nextAssignments.push({ id: generateId(), userId, date: dateStr, templateIds: [], customText: text });
      }
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments, holidays, backgroundImage);
  };

  const replaceAssignment = (userId: string, date: Date, templateIds: string[], customText: string) => {
    const dateStr = formatDateISO(date);
    let nextAssignments = [...assignments];
    const existingIndex = nextAssignments.findIndex(a => a.userId === userId && a.date === dateStr);

    if (templateIds.length === 0 && !customText) {
        if (existingIndex >= 0) {
            nextAssignments = nextAssignments.filter((_, i) => i !== existingIndex);
        }
    } else {
        if (existingIndex >= 0) {
            nextAssignments[existingIndex] = { ...nextAssignments[existingIndex], templateIds, customText };
        } else {
            nextAssignments.push({ id: generateId(), userId, date: dateStr, templateIds, customText });
        }
    }

    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments, holidays, backgroundImage);
  };

  const clearAssignment = (userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    const nextAssignments = assignments.filter(a => !(a.userId === userId && a.date === dateStr));
    setAssignments(nextAssignments);
    saveData(users, templates, nextAssignments, holidays, backgroundImage);
  };

  const moveAssignment = (fromUserId: string, fromDate: Date, toUserId: string, toDate: Date) => {
      const fromDateStr = formatDateISO(fromDate);
      const toDateStr = formatDateISO(toDate);
      if (fromUserId === toUserId && fromDateStr === toDateStr) return;

      const sourceAssignment = assignments.find(a => a.userId === fromUserId && a.date === fromDateStr);
      if (!sourceAssignment) return; 

      let nextAssignments = [...assignments];
      nextAssignments = nextAssignments.filter(a => !(a.userId === fromUserId && a.date === fromDateStr));

      const targetIndex = nextAssignments.findIndex(a => a.userId === toUserId && a.date === toDateStr);
      const newAssignment = {
          id: generateId(), 
          userId: toUserId,
          date: toDateStr,
          templateIds: sourceAssignment.templateIds,
          customText: sourceAssignment.customText
      };

      if (targetIndex >= 0) {
          nextAssignments[targetIndex] = newAssignment;
      } else {
          nextAssignments.push(newAssignment);
      }

      setAssignments(nextAssignments);
      saveData(users, templates, nextAssignments, holidays, backgroundImage);
  };

  const toggleHoliday = (date: Date) => {
      const dateStr = formatDateISO(date);
      let nextHolidays = [...holidays];
      if (nextHolidays.includes(dateStr)) {
          nextHolidays = nextHolidays.filter(h => h !== dateStr);
      } else {
          nextHolidays.push(dateStr);
      }
      setHolidays(nextHolidays);
      saveData(users, templates, assignments, nextHolidays, backgroundImage);
  };

  const setBackgroundImage = (url: string | null) => {
      setSharedBackgroundImage(url);
      saveData(users, templates, assignments, holidays, url);
  };

  const getAssignment = useCallback((userId: string, date: Date) => {
    const dateStr = formatDateISO(date);
    return assignments.find(a => a.userId === userId && a.date === dateStr);
  }, [assignments]);

  return {
    loading, error,
    users, addUser, removeUser, updateUser, reorderUser, // Exported reorderUser
    templates, addTemplate, removeTemplate, updateTemplate,
    holidays, toggleHoliday,
    getAssignment, assignments,
    toggleAssignmentTemplate, updateAssignmentText, clearAssignment, replaceAssignment, moveAssignment,
    backgroundImage, setBackgroundImage
  };
};

import React, { useState } from 'react';
import { User, ShiftTemplate } from '../types';
import { COLORS } from '../constants';
import { Trash2, Plus, User as UserIcon, Calendar, X, Pencil, Save, RotateCcw, ArrowUp, ArrowDown } from 'lucide-react';
import { generateId } from '../utils/idUtils';

interface AdminPanelProps {
  users: User[];
  templates: ShiftTemplate[];
  onAddUser: (u: User) => void;
  onRemoveUser: (id: string) => void;
  onUpdateUser: (u: User) => void;
  onReorderUser: (id: string, direction: 'up' | 'down') => void;
  onAddTemplate: (t: ShiftTemplate) => void;
  onRemoveTemplate: (id: string) => void;
  onUpdateTemplate: (t: ShiftTemplate) => void;
  onClose: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({
  users, templates, onAddUser, onRemoveUser, onUpdateUser, onReorderUser, onAddTemplate, onRemoveTemplate, onUpdateTemplate, onClose
}) => {
  const [activeTab, setActiveTab] = useState<'users' | 'templates'>('users');

  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [newUserName, setNewUserName] = useState('');
  const [newUserRole, setNewUserRole] = useState('');

  const [editingTemplateId, setEditingTemplateId] = useState<string | null>(null);
  const [newTplLabel, setNewTplLabel] = useState('');
  const [newTplColor, setNewTplColor] = useState(COLORS[0].value);
  const [newTplDesc, setNewTplDesc] = useState('');

  const startEditUser = (user: User) => {
    setEditingUserId(user.id);
    setNewUserName(user.name);
    setNewUserRole(user.role);
  };

  const cancelEditUser = () => {
    setEditingUserId(null);
    setNewUserName('');
    setNewUserRole('');
  };

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newUserName.trim()) return;

    if (editingUserId) {
        onUpdateUser({
            id: editingUserId,
            name: newUserName,
            role: newUserRole || 'Employé'
        });
        setEditingUserId(null);
    } else {
        onAddUser({
            id: generateId(),
            name: newUserName,
            role: newUserRole || 'Employé'
        });
    }
    setNewUserName('');
    setNewUserRole('');
  };

  const startEditTemplate = (tpl: ShiftTemplate) => {
    setEditingTemplateId(tpl.id);
    setNewTplLabel(tpl.label);
    setNewTplColor(tpl.color);
    setNewTplDesc(tpl.description || '');
  };

  const cancelEditTemplate = () => {
    setEditingTemplateId(null);
    setNewTplLabel('');
    setNewTplColor(COLORS[0].value);
    setNewTplDesc('');
  };

  const handleTemplateSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTplLabel.trim()) return;

    if (editingTemplateId) {
        onUpdateTemplate({
            id: editingTemplateId,
            label: newTplLabel,
            code: newTplLabel.substring(0, 3).toUpperCase(),
            color: newTplColor,
            description: newTplDesc
        });
        setEditingTemplateId(null);
    } else {
        onAddTemplate({
            id: generateId(),
            label: newTplLabel,
            code: newTplLabel.substring(0, 3).toUpperCase(),
            color: newTplColor,
            description: newTplDesc
        });
    }
    setNewTplLabel('');
    setNewTplDesc('');
    if (editingTemplateId) {
        setNewTplColor(COLORS[0].value);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-800 w-full max-w-2xl rounded-xl shadow-2xl flex flex-col max-h-[90vh] animate-in fade-in zoom-in duration-200 transition-colors m-2">
        <div className="p-4 md:p-6 border-b dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-800/50 rounded-t-xl">
          <h2 className="text-xl md:text-2xl font-bold text-slate-800 dark:text-white">Administration</h2>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors">
            <X className="w-6 h-6 text-slate-500 dark:text-slate-400" />
          </button>
        </div>

        <div className="flex border-b dark:border-slate-700">
          <button
            onClick={() => { setActiveTab('users'); cancelEditTemplate(); }}
            className={`flex-1 py-3 md:py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${activeTab === 'users' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50 dark:bg-blue-900/10' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
          >
            <UserIcon className="w-4 h-4" />
            Utilisateurs
          </button>
          <button
            onClick={() => { setActiveTab('templates'); cancelEditUser(); }}
            className={`flex-1 py-3 md:py-4 text-sm font-semibold flex items-center justify-center gap-2 transition-colors ${activeTab === 'templates' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/50 dark:bg-blue-900/10' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'}`}
          >
            <Calendar className="w-4 h-4" />
            Modèles
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 bg-white dark:bg-slate-800">
          {activeTab === 'users' && (
            <div className="space-y-6">
              <form onSubmit={handleUserSubmit} className={`p-4 rounded-lg border space-y-4 transition-colors ${editingUserId ? 'bg-amber-50 dark:bg-amber-900/10 border-amber-200 dark:border-amber-700' : 'bg-slate-50 dark:bg-slate-900/50 border-slate-200 dark:border-slate-700'}`}>
                <div className="flex items-center justify-between">
                    <h3 className={`font-semibold text-sm uppercase tracking-wide ${editingUserId ? 'text-amber-600 dark:text-amber-400' : 'text-slate-500'}`}>
                        {editingUserId ? 'Modifier l\'utilisateur' : 'Ajouter un utilisateur'}
                    </h3>
                    {editingUserId && (
                        <button type="button" onClick={cancelEditUser} className="text-xs text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-slate-200 flex items-center gap-1">
                            <RotateCcw className="w-3 h-3"/> Annuler
                        </button>
                    )}
                </div>
                <div className="flex flex-col md:flex-row gap-3">
                  <input
                    type="text"
                    placeholder="Nom complet"
                    className="flex-1 px-3 py-2 border dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white dark:bg-slate-800 dark:text-white dark:placeholder-slate-500"
                    value={newUserName}
                    onChange={(e) => setNewUserName(e.target.value)}
                  />
                  <input
                    type="text"
                    placeholder="Rôle (ex: Manager)"
                    className="flex-1 px-3 py-2 border dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white dark:bg-slate-800 dark:text-white dark:placeholder-slate-500"
                    value={newUserRole}
                    onChange={(e) => setNewUserRole(e.target.value)}
                  />
                  <button 
                    type="submit" 
                    className={`text-white px-4 py-2 rounded-lg flex items-center justify-center gap-2 transition-colors ${editingUserId ? 'bg-amber-600 hover:bg-amber-700' : 'bg-blue-600 hover:bg-blue-700'}`}
                  >
                    {editingUserId ? <Save className="w-4 h-4" /> : <Plus className="w-4 h-4" />} 
                    {editingUserId ? 'Enregistrer' : 'Ajouter'}
                  </button>
                </div>
              </form>

              <div className="space-y-2">
                {users.map((user, index) => (
                  <div key={user.id} className={`flex flex-col sm:flex-row sm:items-center justify-between p-3 border dark:border-slate-700 rounded-lg hover:shadow-sm transition-all gap-3 ${editingUserId === user.id ? 'ring-2 ring-amber-400 bg-amber-50 dark:bg-amber-900/20' : 'bg-white dark:bg-slate-700/50'}`}>
                    <div className="flex items-center gap-3">
                      <div className="flex flex-col gap-1 mr-1">
                          <button 
                             onClick={() => onReorderUser(user.id, 'up')}
                             disabled={index === 0}
                             className={`p-1 rounded hover:bg-slate-200 dark:hover:bg-slate-600 ${index === 0 ? 'text-slate-300 dark:text-slate-600 cursor-not-allowed' : 'text-slate-500 dark:text-slate-400'}`}
                          >
                              <ArrowUp className="w-3 h-3"/>
                          </button>
                          <button 
                             onClick={() => onReorderUser(user.id, 'down')}
                             disabled={index === users.length - 1}
                             className={`p-1 rounded hover:bg-slate-200 dark:hover:bg-slate-600 ${index === users.length - 1 ? 'text-slate-300 dark:text-slate-600 cursor-not-allowed' : 'text-slate-500 dark:text-slate-400'}`}
                          >
                              <ArrowDown className="w-3 h-3"/>
                          </button>
                      </div>
                      <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-600 flex items-center justify-center text-slate-600 dark:text-slate-200 font-bold text-xs shrink-0">
                        {user.name.substring(0, 2).toUpperCase()}
                      </div>
                      <div>
                        <div className="font-medium text-slate-800 dark:text-slate-100">{user.name}</div>
                        <div className="text-xs text-slate-500 dark:text-slate-400">{user.role}</div>
                      </div>
                    </div>
                    <div className="flex items-center gap-1 justify-end">
                        <button 
                          onClick={() => startEditUser(user)}
                          className="text-slate-400 hover:text-blue-600 p-2 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-colors"
                          title="Modifier"
                        >
                          <Pencil className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => onRemoveUser(user.id)}
                          className="text-slate-400 hover:text-red-600 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors"
                          title="Supprimer"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                    </div>
                  </div>
                ))}
                {users.length === 0 && <p className="text-center text-slate-400 py-4">Aucun utilisateur.</p>}
              </div>
            </div>
          )}

          {activeTab === 'templates' && (
            <div className="space-y-6">
              <form onSubmit={handleTemplateSubmit} className={`p-4 rounded-lg border space-y-4 transition-colors ${editingTemplateId ? 'bg-amber-50 dark:bg-amber-900/10 border-amber-200 dark:border-amber-700' : 'bg-slate-50 dark:bg-slate-900/50 border-slate-200 dark:border-slate-700'}`}>
                <div className="flex items-center justify-between">
                    <h3 className={`font-semibold text-sm uppercase tracking-wide ${editingTemplateId ? 'text-amber-600 dark:text-amber-400' : 'text-slate-500'}`}>
                        {editingTemplateId ? 'Modifier le modèle' : 'Créer un modèle'}
                    </h3>
                    {editingTemplateId && (
                        <button type="button" onClick={cancelEditTemplate} className="text-xs text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-slate-200 flex items-center gap-1">
                            <RotateCcw className="w-3 h-3"/> Annuler
                        </button>
                    )}
                </div>
                <div className="grid grid-cols-1 gap-3">
                  <input
                    type="text"
                    placeholder="Nom du module (ex: 08h-16h, Télétravail)"
                    className="px-3 py-2 border dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white dark:bg-slate-800 dark:text-white dark:placeholder-slate-500"
                    value={newTplLabel}
                    onChange={(e) => setNewTplLabel(e.target.value)}
                  />
                  <input
                    type="text"
                    placeholder="Description (optionnel)"
                    className="px-3 py-2 border dark:border-slate-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white dark:bg-slate-800 dark:text-white dark:placeholder-slate-500"
                    value={newTplDesc}
                    onChange={(e) => setNewTplDesc(e.target.value)}
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-slate-500 mb-2 block">Couleur</label>
                  <div className="flex flex-wrap gap-2">
                    {COLORS.map(c => (
                      <button
                        key={c.name}
                        type="button"
                        onClick={() => setNewTplColor(c.value)}
                        className={`w-8 h-8 rounded-full shadow-sm transition-transform hover:scale-110 ${c.value.split(' ')[0]} ${newTplColor === c.value ? 'ring-2 ring-offset-2 ring-blue-500 dark:ring-offset-slate-900' : ''}`}
                        title={c.name}
                      />
                    ))}
                  </div>
                  {newTplLabel && (
                     <div className="mt-4">
                        <span className="text-xs text-slate-400 block mb-1">Aperçu :</span>
                        <div className={`inline-flex items-center justify-center px-4 py-2 rounded-md font-bold shadow-sm ${newTplColor}`}>
                           {newTplLabel}
                        </div>
                     </div>
                  )}
                </div>
                <div className="flex justify-end">
                   <button 
                        type="submit" 
                        className={`text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors ${editingTemplateId ? 'bg-amber-600 hover:bg-amber-700' : 'bg-blue-600 hover:bg-blue-700'}`}
                    >
                    {editingTemplateId ? <Save className="w-4 h-4" /> : <Plus className="w-4 h-4" />} 
                    {editingTemplateId ? 'Enregistrer le modèle' : 'Créer le modèle'}
                  </button>
                </div>
              </form>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {templates.map(tpl => (
                  <div key={tpl.id} className={`flex items-center justify-between p-3 border dark:border-slate-600 rounded-lg hover:shadow-sm transition-all border-l-4 dark:bg-slate-700/30 ${tpl.color.replace('bg-', 'border-').split(' ')[0]} ${editingTemplateId === tpl.id ? 'ring-2 ring-amber-400 bg-amber-50 dark:bg-amber-900/20' : ''}`}>
                    <div className="flex-1">
                      <div className="flex items-center gap-2">
                         <span className={`w-3 h-3 rounded-full ${tpl.color.split(' ')[0]}`}></span>
                         <span className="font-bold text-slate-800 dark:text-slate-100">{tpl.label}</span>
                      </div>
                      {tpl.description && <div className="text-xs text-slate-500 dark:text-slate-400 mt-1">{tpl.description}</div>}
                    </div>
                    <div className="flex items-center gap-1">
                        <button 
                          onClick={() => startEditTemplate(tpl)}
                          className="text-slate-400 hover:text-blue-600 p-2 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-full transition-colors"
                          title="Modifier"
                        >
                          <Pencil className="w-4 h-4" />
                        </button>
                        <button 
                          onClick={() => onRemoveTemplate(tpl.id)}
                          className="text-slate-400 hover:text-red-600 p-2 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { User, ShiftTemplate, Assignment } from '../types';
import { getStartOfWeek, addDays, formatDateFr, formatDateISO } from '../utils/dateUtils';
import { ChevronLeft, ChevronRight, Settings, Calendar as CalendarIcon, Check, Eraser, Plus, Type, Copy, Flag } from 'lucide-react';

interface CalendarGridProps {
  currentDate: Date;
  onDateChange: (d: Date) => void;
  users: User[];
  templates: ShiftTemplate[];
  holidays: string[];
  showWeekends: boolean;
  getAssignment: (userId: string, date: Date) => Assignment | undefined;
  onToggleTemplate: (userId: string, date: Date, templateId: string) => void;
  onUpdateText: (userId: string, date: Date, text: string) => void;
  onReplace: (userId: string, date: Date, templateIds: string[], customText: string) => void;
  onClear: (userId: string, date: Date) => void;
  onMoveAssignment: (fromUserId: string, fromDate: Date, toUserId: string, toDate: Date) => void;
  onToggleHoliday: (date: Date) => void;
  onOpenAdmin: () => void;
}

export const CalendarGrid: React.FC<CalendarGridProps> = ({
  currentDate, onDateChange, users, templates, holidays, showWeekends, getAssignment, onToggleTemplate, onUpdateText, onReplace, onClear, onMoveAssignment, onToggleHoliday, onOpenAdmin
}) => {
  const startOfWeek = getStartOfWeek(currentDate);

  // Calculate days to show
  const weekDays = Array.from({ length: 7 }, (_, i) => addDays(startOfWeek, i)).filter(date => {
      if (showWeekends) return true;
      const day = date.getDay();
      return day !== 0 && day !== 6; // 0 = Sunday, 6 = Saturday
  });

  const todayISO = formatDateISO(new Date());

  const [clipboard, setClipboard] = useState<{templateIds: string[], customText: string} | null>(null);
  const [selectedCell, setSelectedCell] = useState<{userId: string, date: Date} | null>(null);
  const [dragOverCell, setDragOverCell] = useState<{userId: string, dateStr: string} | null>(null);

  const [popover, setPopover] = useState<{
    isOpen: boolean;
    userId: string | null;
    date: Date | null;
    x: number;
    y: number;
    maxHeight: number;
    placement: 'above' | 'below';
  }>({ isOpen: false, userId: null, date: null, x: 0, y: 0, maxHeight: 400, placement: 'below' });

  const [localText, setLocalText] = useState('');
  const popoverRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (popover.isOpen && popover.userId && popover.date) {
        const assignment = getAssignment(popover.userId, popover.date);
        setLocalText(assignment?.customText || '');
    }
  }, [popover.isOpen, popover.userId, popover.date, getAssignment]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setPopover({ ...popover, isOpen: false });
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [popover]);

  const handleCellClick = (e: React.MouseEvent, userId: string, date: Date) => {
    setSelectedCell({ userId, date });
    (e.currentTarget as HTMLElement).focus();
  };

  const handleCellDoubleClick = (e: React.MouseEvent | React.KeyboardEvent, userId: string, date: Date) => {
    const target = e.currentTarget as HTMLElement;
    const rect = target.getBoundingClientRect();

    // Better mobile positioning
    let x = rect.left;
    const popoverWidth = 288; // w-72 = 18rem = 288px
    if (x + popoverWidth > window.innerWidth) {
        x = window.innerWidth - popoverWidth - 10;
    }
    if (x < 10) x = 10;

    const spaceBelow = window.innerHeight - rect.bottom - 20;
    const spaceAbove = rect.top - 20;

    let placement: 'above' | 'below' = 'below';
    let y = 0;
    let maxHeight = 400;

    if (spaceBelow < 250 && spaceAbove > spaceBelow) {
        placement = 'above';
        y = window.innerHeight - rect.top + 5;
        maxHeight = Math.min(500, spaceAbove);
    } else {
        placement = 'below';
        y = rect.bottom + 5;
        maxHeight = Math.min(500, spaceBelow);
    }

    setPopover({
      isOpen: true,
      userId,
      date,
      x: x,
      y: y,
      maxHeight,
      placement
    });
  };

  const handleKeyDown = (e: React.KeyboardEvent, userId: string, date: Date) => {
    if (popover.isOpen) return;
    if (e.key === 'Enter') {
        e.preventDefault();
        handleCellDoubleClick(e, userId, date);
    }
    if (e.key === 'Delete' || e.key === 'Backspace') {
        onClear(userId, date);
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'c') {
        e.preventDefault();
        const assignment = getAssignment(userId, date);
        if (assignment) {
            setClipboard({
                templateIds: assignment.templateIds,
                customText: assignment.customText || ''
            });
        } else {
            setClipboard(null);
        }
    }
    if ((e.ctrlKey || e.metaKey) && e.key === 'v') {
        e.preventDefault();
        if (clipboard) {
            onReplace(userId, date, clipboard.templateIds, clipboard.customText);
        }
    }
  };

  const handleTextChange = (e: React.ChangeEvent<HTMLInputElement>) => {
      setLocalText(e.target.value);
      if (popover.userId && popover.date) {
          onUpdateText(popover.userId, popover.date, e.target.value);
      }
  };

  const handleDragStart = (e: React.DragEvent, userId: string, date: Date) => {
    const assignment = getAssignment(userId, date);
    if (!assignment || (assignment.templateIds.length === 0 && !assignment.customText)) {
        e.preventDefault();
        return;
    }
    e.dataTransfer.setData('application/json', JSON.stringify({ userId, date: formatDateISO(date) }));
    e.dataTransfer.effectAllowed = 'move';
    const target = e.currentTarget as HTMLElement;
    target.style.opacity = '0.5';
  };

  const handleDragEnd = (e: React.DragEvent) => {
    const target = e.currentTarget as HTMLElement;
    target.style.opacity = '1';
    setDragOverCell(null);
  };

  const handleDragOver = (e: React.DragEvent, userId: string, date: Date) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    const dateStr = formatDateISO(date);
    if (dragOverCell?.userId !== userId || dragOverCell?.dateStr !== dateStr) {
        setDragOverCell({ userId, dateStr });
    }
  };

  const handleDrop = (e: React.DragEvent, targetUserId: string, targetDate: Date) => {
    e.preventDefault();
    setDragOverCell(null);
    try {
        const data = JSON.parse(e.dataTransfer.getData('application/json'));
        if (data && data.userId && data.date) {
            const sourceDate = new Date(data.date);
            onMoveAssignment(data.userId, sourceDate, targetUserId, targetDate);
        }
    } catch (err) {
        console.error("Drop failed", err);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white/95 dark:bg-slate-800/95 shadow-sm border dark:border-slate-700 rounded-xl overflow-hidden transition-colors backdrop-blur-sm">
      <div className="flex flex-col sm:flex-row items-center justify-between p-4 border-b dark:border-slate-700 bg-white/50 dark:bg-slate-800/50 transition-colors gap-3">
        <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-start">
          <div className="flex bg-slate-100 dark:bg-slate-700 rounded-lg p-1 border border-slate-200 dark:border-slate-600">
            <button onClick={() => onDateChange(addDays(currentDate, -7))} className="p-1 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all text-slate-600 dark:text-slate-300"><ChevronLeft className="w-5 h-5" /></button>
            <button onClick={() => onDateChange(new Date())} className="px-3 py-1 text-sm font-medium text-slate-600 dark:text-slate-200 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all">Aujourd'hui</button>
            <button onClick={() => onDateChange(addDays(currentDate, 7))} className="p-1 hover:bg-white dark:hover:bg-slate-600 hover:shadow-sm rounded-md transition-all text-slate-600 dark:text-slate-300"><ChevronRight className="w-5 h-5" /></button>
          </div>
          <h2 className="text-lg font-bold text-slate-800 dark:text-white capitalize flex items-center gap-2">
            <CalendarIcon className="w-5 h-5 text-blue-600 dark:text-blue-400 hidden sm:block" />
            <span className="sm:hidden">{new Intl.DateTimeFormat('fr-FR', { month: 'short', year: '2-digit' }).format(currentDate)}</span>
            <span className="hidden sm:inline">{new Intl.DateTimeFormat('fr-FR', { month: 'long', year: 'numeric' }).format(currentDate)}</span>
          </h2>
        </div>
        <button onClick={onOpenAdmin} className="w-full sm:w-auto flex items-center justify-center gap-2 px-4 py-2 bg-slate-900 dark:bg-slate-700 text-white text-sm font-medium rounded-lg hover:bg-slate-700 dark:hover:bg-slate-600 transition-colors shadow-sm">
          <Settings className="w-4 h-4" />
          <span>Gérer l'équipe</span>
        </button>
      </div>

      <div className="flex-1 overflow-auto relative touch-pan-x touch-pan-y">
        <table className="w-full border-collapse min-w-[800px] md:min-w-[1000px]">
          <thead className="bg-slate-50/90 dark:bg-slate-900/90 sticky top-0 z-20 shadow-sm transition-colors backdrop-blur-sm">
            <tr>
              <th className="p-4 text-left border-b border-r dark:border-slate-700 w-48 md:w-64 bg-slate-50/90 dark:bg-slate-900/90 sticky left-0 z-30 backdrop-blur-sm">
                <span className="text-xs font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider">Membres</span>
              </th>
              {weekDays.map((date) => {
                const dateISO = formatDateISO(date);
                const isToday = dateISO === todayISO;
                const isHoliday = holidays.includes(dateISO);
                return (
                  <th key={dateISO} className={`p-3 text-center border-b border-r dark:border-slate-700 min-w-[100px] md:min-w-[120px] relative overflow-hidden ${isToday ? 'bg-blue-50/50 dark:bg-blue-900/20' : ''} ${isHoliday ? 'bg-red-50 dark:bg-red-900/20' : ''}`}>
                    <div className="flex flex-col items-center justify-center relative z-10">
                      <span className={`text-xs uppercase font-bold mb-1 ${isToday ? 'text-blue-600 dark:text-blue-400' : isHoliday ? 'text-red-600 dark:text-red-400' : 'text-slate-400 dark:text-slate-500'}`}>
                        {new Intl.DateTimeFormat('fr-FR', { weekday: 'short' }).format(date)}
                      </span>
                      <span className={`text-xl font-light w-8 h-8 flex items-center justify-center rounded-full ${isToday ? 'bg-blue-600 text-white shadow-md' : isHoliday ? 'text-red-600 dark:text-red-400 font-normal ring-1 ring-red-200 dark:ring-red-800' : 'text-slate-700 dark:text-slate-300'}`}>
                        {date.getDate()}
                      </span>
                    </div>
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id} className="group hover:bg-slate-50/50 dark:hover:bg-slate-700/30 transition-colors">
                <td className="p-4 border-b border-r dark:border-slate-700 bg-white/90 dark:bg-slate-800/90 sticky left-0 z-10 group-hover:bg-slate-50/90 dark:group-hover:bg-slate-700/90 border-r-slate-200 dark:border-r-slate-700 transition-colors backdrop-blur-sm">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 md:w-10 md:h-10 rounded-full bg-gradient-to-br from-blue-500 to-indigo-600 text-white flex items-center justify-center font-bold shadow-sm text-xs md:text-sm">{user.name.charAt(0)}</div>
                    <div className="min-w-0"><div className="font-semibold text-slate-900 dark:text-slate-100 text-xs md:text-sm truncate">{user.name}</div><div className="text-[10px] md:text-xs text-slate-500 dark:text-slate-400 truncate">{user.role}</div></div>
                  </div>
                </td>
                {weekDays.map((date) => {
                  const dateISO = formatDateISO(date);
                  const assignment = getAssignment(user.id, date);
                  const activeTemplateIds = assignment?.templateIds || [];
                  const hasCustomText = !!assignment?.customText;
                  const isEmpty = activeTemplateIds.length === 0 && !hasCustomText;
                  const isToday = dateISO === todayISO;
                  const isHoliday = holidays.includes(dateISO);
                  const isSelected = selectedCell?.userId === user.id && selectedCell?.date.getTime() === date.getTime();
                  const isDragOver = dragOverCell?.userId === user.id && dragOverCell?.dateStr === dateISO;

                  return (
                    <td key={dateISO} className={`p-1 border-b border-r dark:border-slate-700 cursor-pointer relative transition-all align-top h-20 md:h-24 outline-none ${isToday ? 'bg-blue-50/10 dark:bg-blue-900/10' : ''} ${isHoliday ? 'bg-red-50/30 dark:bg-red-900/10' : ''} ${isDragOver ? 'bg-blue-100 dark:bg-blue-800/50 ring-2 ring-inset ring-blue-400' : 'focus:bg-blue-50/30 dark:focus:bg-blue-900/20'}`} onClick={(e) => handleCellClick(e, user.id, date)} onDoubleClick={(e) => handleCellDoubleClick(e, user.id, date)} onKeyDown={(e) => handleKeyDown(e, user.id, date)} onDragOver={(e) => handleDragOver(e, user.id, date)} onDrop={(e) => handleDrop(e, user.id, date)} tabIndex={0}>
                        <div className={`w-full h-full min-h-[4rem] rounded-md transition-all flex flex-col overflow-hidden relative z-10 ${isSelected ? 'ring-2 ring-blue-500 z-10' : ''} ${isEmpty ? 'border-2 border-dashed border-transparent hover:border-blue-200 dark:hover:border-slate-600' : 'bg-white dark:bg-slate-700 shadow-sm border border-slate-200 dark:border-slate-600'}`} draggable={!isEmpty} onDragStart={(e) => handleDragStart(e, user.id, date)} onDragEnd={handleDragEnd}>
                        {isEmpty ? (<div className="w-full h-full flex items-center justify-center"><Plus className={`w-5 h-5 text-slate-300 dark:text-slate-600 ${isSelected ? 'text-blue-400' : ''}`} /></div>) : (
                          <><div className="flex-1 flex flex-col w-full h-full">
                                {activeTemplateIds.map(tid => {
                                    const tpl = templates.find(t => t.id === tid);
                                    if (!tpl) return null;
                                    return (<div key={tid} className={`flex-1 flex items-center justify-center px-1 md:px-2 text-[10px] md:text-xs font-bold ${tpl.color} w-full border-b border-black/10 last:border-0`} title={tpl.label}><span className="truncate text-center shadow-sm">{tpl.label}</span></div>);
                                })}
                            </div>
                            {hasCustomText && (<div className={`px-1 py-0.5 bg-yellow-50 dark:bg-yellow-900/30 text-[9px] md:text-[10px] text-slate-700 dark:text-yellow-100 leading-tight border-t border-slate-100 dark:border-slate-600 text-center truncate ${activeTemplateIds.length === 0 ? 'h-full flex items-center justify-center font-medium text-xs' : ''}`}>{assignment.customText}</div>)}</>
                        )}
                      </div>
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {popover.isOpen && popover.userId && popover.date && (
        <div 
          ref={popoverRef}
          className={`fixed bg-white dark:bg-slate-800 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-600 z-50 w-72 p-3 animate-in fade-in zoom-in-95 duration-100 flex flex-col gap-3 origin-${popover.placement === 'below' ? 'top-left' : 'bottom-left'} overflow-y-auto`}
          style={{ 
            left: popover.x, 
            top: popover.placement === 'below' ? popover.y : 'auto', 
            bottom: popover.placement === 'above' ? popover.y : 'auto',
            maxHeight: popover.maxHeight
          }}
        >
          <div className="relative sticky top-0 bg-white dark:bg-slate-800 z-10 pb-1">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><Type className="h-4 w-4 text-slate-400" /></div>
             <input autoFocus type="text" placeholder="Note personnalisée..." className="w-full pl-9 pr-3 py-2 text-sm border rounded-lg focus:ring-2 focus:ring-blue-500 focus:outline-none bg-white dark:bg-slate-900 dark:border-slate-600 dark:text-white" value={localText} onChange={handleTextChange} />
          </div>

          <div className="h-px bg-slate-100 dark:bg-slate-700"></div>

          <label className="flex items-center gap-3 p-2 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-700 cursor-pointer border border-transparent hover:border-slate-200 transition-all">
             <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-colors ${holidays.includes(formatDateISO(popover.date)) ? 'bg-red-100 text-red-600' : 'bg-slate-100 text-slate-400 dark:bg-slate-700'}`}><Flag className="w-4 h-4" /></div>
             <div className="flex-1"><div className="text-sm font-medium text-slate-800 dark:text-slate-200">Jour Férié</div><div className="text-[10px] text-slate-500 dark:text-slate-400">Pour toute l'équipe</div></div>
             <input type="checkbox" className="w-4 h-4 rounded text-blue-600" checked={holidays.includes(formatDateISO(popover.date))} onChange={() => onToggleHoliday(popover.date!)} />
          </label>

          <div className="h-px bg-slate-100 dark:bg-slate-700"></div>

          <div className="space-y-1">
             <div className="text-xs font-bold text-slate-400 uppercase px-1 mb-2">Modules</div>
            {templates.map(tpl => {
               const assignment = getAssignment(popover.userId!, popover.date!);
               const isSelected = assignment?.templateIds.includes(tpl.id);
               return (
                  <button key={tpl.id} onClick={() => onToggleTemplate(popover.userId!, popover.date!, tpl.id)} className={`w-full text-left p-2 rounded-lg text-sm font-medium transition-all flex items-center gap-2 group border ${isSelected ? 'bg-blue-50 dark:bg-blue-900/30 border-blue-200 dark:border-blue-700' : 'border-transparent hover:bg-slate-50 dark:hover:bg-slate-700'}`}>
                    <div className={`w-4 h-4 rounded flex items-center justify-center border ${isSelected ? 'bg-blue-600 border-blue-600' : 'border-slate-300 dark:border-slate-500 bg-white dark:bg-slate-700'}`}>{isSelected && <Check className="w-3 h-3 text-white" />}</div>
                    <span className={`w-3 h-3 rounded-full ${tpl.color.split(' ')[0]}`}></span>
                    <span className="flex-1 truncate dark:text-slate-200">{tpl.label}</span>
                  </button>
               );
            })}
          </div>

          <div className="h-px bg-slate-100 dark:bg-slate-700 sticky bottom-10 bg-white dark:bg-slate-800 z-10"></div>
          <button onClick={() => { onClear(popover.userId!, popover.date!); setPopover({...popover, isOpen: false}); }} className="w-full text-left p-2 rounded-lg text-sm font-medium text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors flex items-center justify-center gap-2 sticky bottom-0 bg-white dark:bg-slate-800 z-10"><Eraser className="w-4 h-4" />Tout effacer</button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { CalendarGrid } from './components/CalendarGrid';
import { AdminPanel } from './components/AdminPanel';
import { DisplaySettings } from './components/DisplaySettings';
import { usePlanner } from './hooks/usePlanner';
import { Loader2, AlertCircle, Moon, Sun, Layout } from 'lucide-react';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isAdminOpen, setIsAdminOpen] = useState(false);
  const [isDisplaySettingsOpen, setIsDisplaySettingsOpen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
